// @vitest-environment jsdom
import { act, renderHook } from '@testing-library/react';
import { describe, expect, it, vi } from 'vitest';
import { useClipResize } from './useClipResize';
import { configToRows, type TimelineData } from '../lib/timeline-data';
import { getConfigSignature, getStableConfigSignature } from '../lib/config-utils';
import type { TimelineApplyEdit } from './timeline-state-types';
import type { TimelineConfig } from '../types';
import type { TimelineAction, TimelineRow } from '../types/timeline-canvas';

/**
 * Build a TimelineData with a pinned group of N hold clips on V1, each 1s long,
 * starting at `at=0, 1, 2, ...`. Optionally a single "free" clip outside the group.
 */
function makeData(opts: {
  groupClipIds: string[];
  groupMode?: 'images' | 'video';
  freeClips?: Array<{ id: string; at: number; hold: number }>;
}): TimelineData {
  const { groupClipIds, groupMode = 'images', freeClips = [] } = opts;

  const config: TimelineConfig = {
    output: { resolution: '1920x1080', fps: 30, file: 'out.mp4' },
    tracks: [
      { id: 'V1', kind: 'visual', label: 'V1' },
      { id: 'V2', kind: 'visual', label: 'V2' },
    ],
    clips: [
      ...groupClipIds.map((id, index) => ({
        id,
        at: index,
        track: 'V1' as const,
        clipType: 'hold' as const,
        hold: 1,
      })),
      ...freeClips.map((c) => ({
        id: c.id,
        at: c.at,
        track: 'V2' as const,
        clipType: 'hold' as const,
        hold: c.hold,
      })),
    ],
    pinnedShotGroups: [
      {
        shotId: 'shot-1',
        trackId: 'V1',
        clipIds: [...groupClipIds],
        mode: groupMode,
      },
    ],
  };

  const rowData = configToRows(config);
  const resolvedConfig = {
    output: { ...config.output },
    tracks: (config.tracks ?? []).map((t) => ({ ...t })),
    clips: config.clips.map((clip) => ({ ...clip, assetEntry: undefined })),
    registry: {},
  };
  return {
    config,
    configVersion: 1,
    registry: { assets: {} },
    resolvedConfig,
    rows: rowData.rows,
    meta: rowData.meta,
    effects: rowData.effects,
    assetMap: {},
    output: { ...config.output },
    tracks: (config.tracks ?? []).map((t) => ({ ...t })),
    clipOrder: rowData.clipOrder,
    signature: getConfigSignature(resolvedConfig),
    stableSignature: getStableConfigSignature(config, { assets: {} }),
  };
}

function getAction(rows: TimelineRow[], rowId: string, actionId: string): TimelineAction | undefined {
  return rows.find((r) => r.id === rowId)?.actions.find((a) => a.id === actionId);
}

describe('useClipResize — soft-tag grouped resize', () => {
  it('first-edge (left edge of first clip in group): only first clip changes', () => {
    const data = makeData({ groupClipIds: ['a', 'b', 'c'] });
    const dataRef = { current: data };
    const applyEdit = vi.fn<Parameters<TimelineApplyEdit>>();

    const { result } = renderHook(() => useClipResize({ dataRef, applyEdit }));

    const row = data.rows[0];
    const actionA = getAction(data.rows, 'V1', 'a')!;

    act(() => {
      result.current.onActionResizeStart({ action: actionA, row, dir: 'left' });
    });
    // Move first clip's left edge from 0 to 0.3 → clip 'a' shrinks to hold=0.7, others unchanged.
    act(() => {
      result.current.onActionResizeEnd({
        action: actionA,
        row,
        dir: 'left',
        start: 0.3,
        end: 1,
      });
    });

    expect(applyEdit).toHaveBeenCalledOnce();
    const [mutation] = applyEdit.mock.calls[0];
    expect(mutation.type).toBe('rows');
    if (mutation.type !== 'rows') throw new Error('expected rows');

    // Only clip 'a' should have a hold update.
    expect(mutation.metaUpdates?.a).toMatchObject({ hold: expect.closeTo(0.7, 5) });
    expect(mutation.metaUpdates?.b).not.toHaveProperty('hold');
    expect(mutation.metaUpdates?.c).not.toHaveProperty('hold');

    // Rows: clip 'a' new bounds, 'b' and 'c' unchanged.
    const a = getAction(mutation.rows, 'V1', 'a')!;
    const b = getAction(mutation.rows, 'V1', 'b')!;
    const c = getAction(mutation.rows, 'V1', 'c')!;
    expect(a.start).toBeCloseTo(0.3, 5);
    expect(a.end).toBeCloseTo(1, 5);
    expect(b.start).toBeCloseTo(1, 5);
    expect(b.end).toBeCloseTo(2, 5);
    expect(c.start).toBeCloseTo(2, 5);
    expect(c.end).toBeCloseTo(3, 5);
  });

  it('last-edge (right edge of last clip in group): only last clip changes', () => {
    const data = makeData({ groupClipIds: ['a', 'b', 'c'] });
    const dataRef = { current: data };
    const applyEdit = vi.fn<Parameters<TimelineApplyEdit>>();

    const { result } = renderHook(() => useClipResize({ dataRef, applyEdit }));

    const row = data.rows[0];
    const actionC = getAction(data.rows, 'V1', 'c')!;

    act(() => {
      result.current.onActionResizeStart({ action: actionC, row, dir: 'right' });
    });
    // Extend clip 'c' from end=3 to end=3.5 → hold grows to 1.5.
    act(() => {
      result.current.onActionResizeEnd({
        action: actionC,
        row,
        dir: 'right',
        start: 2,
        end: 3.5,
      });
    });

    expect(applyEdit).toHaveBeenCalledOnce();
    const [mutation] = applyEdit.mock.calls[0];
    if (mutation.type !== 'rows') throw new Error('expected rows');

    expect(mutation.metaUpdates?.c).toMatchObject({ hold: expect.closeTo(1.5, 5) });
    expect(mutation.metaUpdates?.a).not.toHaveProperty('hold');
    expect(mutation.metaUpdates?.b).not.toHaveProperty('hold');

    const a = getAction(mutation.rows, 'V1', 'a')!;
    const b = getAction(mutation.rows, 'V1', 'b')!;
    const c = getAction(mutation.rows, 'V1', 'c')!;
    expect(a.start).toBe(0);
    expect(b.start).toBe(1);
    expect(c.start).toBe(2);
    expect(c.end).toBeCloseTo(3.5, 5);
  });

  it('interior boundary (drag clip[1] right-edge): two adjacent clips trade duration', () => {
    const data = makeData({ groupClipIds: ['a', 'b', 'c'] });
    const dataRef = { current: data };
