it('sequence: resize last clip → then interior boundary → both commits emit rows mutations', () => {
  // Simulate a sequence where dataRef.current gets updated between resizes
  // (as the parent hook would do on commit).
  const initial = makeData({ groupClipIds: ['a', 'b', 'c'] });
  const dataRef = { current: initial };
  const applyEdit = vi.fn<Parameters<TimelineApplyEdit>>((mutation) => {
    if (mutation.type !== 'rows') return;
    // Simulate materializeData: reflect the new rows + meta into dataRef.
    const nextMeta = { ...dataRef.current.meta };
    if (mutation.metaUpdates) {
      for (const [id, patch] of Object.entries(mutation.metaUpdates)) {
        nextMeta[id] = { ...nextMeta[id], ...patch } as typeof nextMeta[string];
      }
    }
    dataRef.current = {
      ...dataRef.current,
      rows: mutation.rows,
      meta: nextMeta,
    };
  });

