  action: TimelineAction,
  row: TimelineRow,
  dir: ResizeDir,
) => {
  if (event.button !== 0) return;

  // Decide which kind of session this is BEFORE touching state, so the
  // commit fn lookup for outer-edge resizes happens early and we can
  // bail without polluting refs if it returns null.
  const groupForAction = shotGroups.find((candidate) => (
    candidate.rowId === row.id && candidate.clipIds.includes(action.id)
  ));

  let nextSession: ResizeSession | null = null;
  let initialOverrides: Record<string, ResizeOverride> = {};
  let initialPreviewKeys: Array<{ key: string; value: ResizeOverride }> = [];

  if (groupForAction) {
    const childIndex = groupForAction.clipIds.indexOf(action.id);
    const adjacentIndex = dir === 'left' ? childIndex - 1 : childIndex + 1;
    const isInterior = adjacentIndex >= 0 && adjacentIndex < groupForAction.clipIds.length;

    if (isInterior) {
      const adjacentClipId = groupForAction.clipIds[adjacentIndex]!;
      const adjacentAction = row.actions.find((c) => c.id === adjacentClipId);
      if (adjacentAction) {
        const pairStart = dir === 'left' ? adjacentAction.start : action.start;
        const pairEnd = dir === 'left' ? action.end : adjacentAction.end;
        const minChildDur = 0.05;
        nextSession = {
          kind: 'group-child-boundary',
          pointerId: event.pointerId,
          actionId: action.id,
          rowId: row.id,
          dir,
          initialStart: action.start,
          initialEnd: action.end,
          initialClientX: event.clientX,
          adjacentActionId: adjacentClipId,
          adjacentInitialStart: adjacentAction.start,
          adjacentInitialEnd: adjacentAction.end,
          minBoundary: pairStart + minChildDur,
          maxBoundary: pairEnd - minChildDur,
        };
        initialOverrides = {
          [action.id]: { start: action.start, end: action.end },
          [adjacentClipId]: { start: adjacentAction.start, end: adjacentAction.end },
        };
        initialPreviewKeys = [
          { key: action.id, value: { start: action.start, end: action.end } },
          { key: adjacentClipId, value: { start: adjacentAction.start, end: adjacentAction.end } },
        ];
      }
    } else {
      // Outer group edge — first child's left or last child's right.
      // Look up the commit fn synchronously; if it returns null we don't
      // intercept the click at all and the user gets normal pointer flow.
      const positioned = positionedShotGroups.find((c) => (
        c.shotId === groupForAction.shotId && c.rowId === row.id
      ));
      const commitResize = positioned
        ? onShotGroupEdgeResize?.({ shotId: positioned.shotId, trackId: positioned.rowId }, dir) ?? null
        : null;
      if (positioned && commitResize) {
        const groupKey = `${positioned.shotId}:${positioned.rowId}`;
        // Capture each child's current absolute start/end so we can
        // drive per-clip preview overrides during the drag.
        const groupChildrenSnapshot = positioned.clipIds
          .map((clipId) => row.actions.find((a) => a.id === clipId))
          .filter((a): a is TimelineAction => !!a)
          .map((a) => ({ clipId: a.id, start: a.start, end: a.end }));
        nextSession = {
          kind: 'group-edge',
          pointerId: event.pointerId,
          actionId: action.id,
          rowId: row.id,
          dir,
          initialClientX: event.clientX,
          shotId: positioned.shotId,
          groupInitialStart: positioned.start,
          groupInitialEnd: positioned.end,
          groupClipIds: [...positioned.clipIds],
          groupChildrenSnapshot,
          commitResize,
        };
        initialOverrides = {
          [groupKey]: { start: positioned.start, end: positioned.end },
          ...Object.fromEntries(groupChildrenSnapshot.map((c) => [
            c.clipId,
            { start: c.start, end: c.end },
          ])),
        };
        initialPreviewKeys = [
          { key: groupKey, value: { start: positioned.start, end: positioned.end } },
          ...groupChildrenSnapshot.map((c) => ({
            key: c.clipId,
            value: { start: c.start, end: c.end },
          })),
        ];
      }
    }
  }

  if (!nextSession) {
    // Free clip resize (or grouped clip where session creation failed).
    // Falls through to the regular per-clip session — same behavior as
    // before grouped resize existed.
    const resizeLimits = getAudioResizeLimits(dataRef.current, action, row, dir);
    nextSession = {
      kind: 'clip',
      pointerId: event.pointerId,
      actionId: action.id,
      rowId: row.id,
      dir,
      initialStart: action.start,
      initialEnd: action.end,
      initialClientX: event.clientX,
      ...resizeLimits,
    };
    initialOverrides = {
      [action.id]: { start: action.start, end: action.end },
    };
    initialPreviewKeys = [
      { key: action.id, value: { start: action.start, end: action.end } },
    ];
  }

  resizeSessionRef.current = nextSession;
  for (const { key, value } of initialPreviewKeys) {
    resizePreviewRef.current[key] = value;
  }
  setResizeClampedActionId(null);
  setResizeOverrides((current) => ({ ...current, ...initialOverrides }));

  if (nextSession.kind === 'clip' || nextSession.kind === 'group-child-boundary') {
    onActionResizeStart?.({ action, row, dir });
  }
  if (interactionStateRef) {
    interactionStateRef.current.resize = true;
  }
  pendingOpsRef.current += 1;
  event.currentTarget.setPointerCapture(event.pointerId);
  event.preventDefault();
  event.stopPropagation();
}, [dataRef, interactionStateRef, onActionResizeStart, onShotGroupEdgeResize, positionedShotGroups, shotGroups]);

const handleResizePointerMove = useCallback((event: ReactPointerEvent<HTMLDivElement>) => {
  const session = resizeSessionRef.current;
  if (!session || session.pointerId !== event.pointerId) return;
  updateResize(session, event.clientX);
}, [updateResize]);

// Backwards-compat alias for any external test wiring.
const handleShotGroupResizePointerMove = handleResizePointerMove;

