export type CustomEffectEntry = {
  code: string;
  category?: 'entrance' | 'exit' | 'continuous';
};

export type PinnedShotImageClipSnapshot = {
  clipId: string;
  assetKey?: string;
  meta: {
    clipType?: ClipType;
    from?: number;
    to?: number;
    speed?: number;
    hold?: number;
    volume?: number;
    x?: number;
    y?: number;
    width?: number;
    height?: number;
    cropTop?: number;
    cropBottom?: number;
    cropLeft?: number;
    cropRight?: number;
    opacity?: number;
    text?: TextClipData;
    entrance?: ClipEntrance;
    exit?: ClipExit;
    continuous?: ClipContinuous;
    transition?: ClipTransition;
    effects?: TimelineEffect[] | Record<string, number>;
  };
};

// `clipIds` is ordered left-to-right by each clip's live `at` and must be rebuilt whenever group membership or ordering changes.
//
// `start` and `children` are LEGACY projection-model fields kept for
// backward compatibility while the rollback to the soft-tag model is in
// progress. Soft-tag readers should ignore them; soft-tag writers should
// not set them. They will be dropped from this type once every callsite
// stops touching them.
export type PinnedShotGroup = {
  shotId: string;
  trackId: string;
  clipIds: string[];
  mode?: 'images' | 'video';
  videoAssetKey?: string;
  imageClipSnapshot?: PinnedShotImageClipSnapshot[];
  /** @deprecated Legacy projection-model field. Soft-tag model derives this from clips. */
  start?: number;
  /** @deprecated Legacy projection-model field. Soft-tag model derives this from clips. */
  children?: Array<{ clipId: string; offset: number; duration: number }>;
};

export type TimelineConfig = {
  output: TimelineOutput;
  clips: TimelineClip[];
  tracks?: TrackDefinition[];
  customEffects?: Record<string, CustomEffectEntry>;
  pinnedShotGroups?: PinnedShotGroup[];
};

export type AssetRegistryEntry = {
  file: string;
  type?: string;
  duration?: number;
  resolution?: string;
  fps?: number;
  generationId?: string;
  variantId?: string;
  thumbnailUrl?: string;
};

export type AssetRegistry = {
  assets: Record<string, AssetRegistryEntry>;
};

export type ResolvedAssetRegistryEntry = AssetRegistryEntry & {
  src: string;
};

export type ResolvedTimelineClip = TimelineClip & {
  assetEntry?: ResolvedAssetRegistryEntry;
};

export type ResolvedTimelineConfig = {
  output: TimelineOutput;
  tracks: TrackDefinition[];
  clips: ResolvedTimelineClip[];
  registry: Record<string, ResolvedAssetRegistryEntry>;
};

export type TimelineCompositionProps = {
  config?: ResolvedTimelineConfig;
  preview?: boolean;
};

import { describe, expect, it } from 'vitest';
import { repairConfig } from '@/tools/video-editor/lib/migrate';
import { configToRows, rowsToConfig } from '@/tools/video-editor/lib/timeline-data';
import type { TimelineConfig } from '@/tools/video-editor/types';

describe('repairConfig — legacy pinnedShotGroups migration', () => {
  const buildLegacyConfig = (): TimelineConfig => ({
    output: { resolution: '1920x1080', fps: 30, file: 'out.mp4' },
    tracks: [{ id: 'V1', kind: 'visual', label: 'V1' }],
    clips: [
      { id: 'clip-a', at: 0, track: 'V1', clipType: 'hold', hold: 1 },
      { id: 'clip-b', at: 1, track: 'V1', clipType: 'hold', hold: 2 },
      { id: 'clip-c', at: 3, track: 'V1', clipType: 'hold', hold: 1.5 },
    ],
    // Legacy projection-shape group with `start` and `children` fields.
    pinnedShotGroups: [
      {
        shotId: 'shot-1',
        trackId: 'V1',
        clipIds: ['clip-a', 'clip-b', 'clip-c'],
        mode: 'images',
        // `as unknown as ...` escape hatch — the runtime file has extra legacy fields
        // even though the TS type no longer allows them.
        ...({
          start: 0,
          children: [
            { clipId: 'clip-a', offset: 0, duration: 1 },
            { clipId: 'clip-b', offset: 1, duration: 2 },
            { clipId: 'clip-c', offset: 3, duration: 1.5 },
          ],
        } as unknown as object),
      },
    ] as TimelineConfig['pinnedShotGroups'],
  });

  it('strips legacy `start`/`children` and derives clipIds from children', () => {
    const repaired = repairConfig(buildLegacyConfig());
    const [group] = repaired.pinnedShotGroups ?? [];
    expect(group).toBeDefined();
    expect(group).toMatchObject({
      shotId: 'shot-1',
      trackId: 'V1',
      clipIds: ['clip-a', 'clip-b', 'clip-c'],
      mode: 'images',
    });
    // Legacy fields must be gone.
    expect(Object.prototype.hasOwnProperty.call(group, 'start')).toBe(false);
    expect(Object.prototype.hasOwnProperty.call(group, 'children')).toBe(false);
  });

  it('preserves clipIds when legacy `children` array is missing', () => {
    const config = buildLegacyConfig();
    const [g] = config.pinnedShotGroups ?? [];
    const legacyWithoutChildren = {
      shotId: g.shotId,
      trackId: g.trackId,
      clipIds: ['clip-a', 'clip-b', 'clip-c'],
      mode: g.mode,
      ...({ start: 0 } as unknown as object),
    };
    config.pinnedShotGroups = [legacyWithoutChildren] as TimelineConfig['pinnedShotGroups'];

    const repaired = repairConfig(config);
    const [repairedGroup] = repaired.pinnedShotGroups ?? [];
