      ],
      pinnedShotGroups: [
        { shotId: 'shot-1', trackId: 'V1', clipIds: ['clip-a'], mode: 'images' },
      ],
    };
    const repaired = repairConfig(config);
    expect(repaired.pinnedShotGroups).toBe(config.pinnedShotGroups);
