export function reorderTracksByDirection(
  tracks: TrackDefinition[],
  trackId: string,
  direction: -1 | 1,
): TrackDefinition[] {
  const index = tracks.findIndex((track) => track.id === trackId);
  if (index < 0) {
    return tracks;
  }

  const trackKind = tracks[index]?.kind;
  let targetIndex = index + direction;
  while (
    targetIndex >= 0 &&
    targetIndex < tracks.length &&
    tracks[targetIndex]?.kind !== trackKind
  ) {
    targetIndex += direction;
  }

  if (targetIndex < 0 || targetIndex >= tracks.length) {
    return tracks;
  }

  const nextTracks = [...tracks];
  [nextTracks[index], nextTracks[targetIndex]] = [nextTracks[targetIndex], nextTracks[index]];
  return nextTracks;
}

export function moveTrackWithinKind(
  tracks: TrackDefinition[],
  activeId: string,
  overId: string,
): TrackDefinition[] {
  const activeIndex = tracks.findIndex((track) => track.id === activeId);
  const overIndex = tracks.findIndex((track) => track.id === overId);
  if (activeIndex < 0 || overIndex < 0 || activeIndex === overIndex) {
    return tracks;
  }

  return arrayMove(tracks, activeIndex, overIndex);
}

/**
 * Compute the effect of translating every member of a pinned shot group by
 * (deltaTime, targetRowId). Returns next rows + per-clip metaUpdates (including
 * track patches) + clipOrderOverride + a soft-tag override for the dragged
 * group. Shared by moveClipToRow, createTrackAndMoveClip, and the batch move
 * path in moveSelectedClipsToTrack. Pure; does not touch dataRef.
 */
function translateGroupMembers({
  current,
  group,
  targetRowId,
  deltaTime,
}: {
  current: TimelineData;
  group: PinnedShotGroup;
  targetRowId: string;
  deltaTime: number;
}): {
  nextRows: TimelineRow[];
  metaUpdates: Record<string, Partial<TimelineData['meta'][string]>>;
  nextClipOrder: TimelineData['clipOrder'];
  pinnedShotGroupsOverride: PinnedShotGroup[];
} {
  const memberSet = new Set(group.clipIds);
  const sourceTrackId = group.trackId;

  // Capture each member's current action so we can translate it.
  const memberActions = new Map<string, { start: number; end: number; effectId: string }>();
  for (const row of current.rows) {
    for (const action of row.actions) {
      if (memberSet.has(action.id)) {
        memberActions.set(action.id, { start: action.start, end: action.end, effectId: action.effectId });
      }
    }
  }

  // Remove members from their current rows, then add them (translated) to the target row.
  let nextRows = current.rows.map((row) => ({
    ...row,
    actions: row.actions.filter((a) => !memberSet.has(a.id)),
  }));
  const translatedActions = group.clipIds
    .map((clipId) => {
      const original = memberActions.get(clipId);
      if (!original) return null;
      return {
        id: clipId,
        start: original.start + deltaTime,
        end: original.end + deltaTime,
        effectId: original.effectId,
      };
    })
    .filter((a): a is NonNullable<typeof a> => a !== null);

  nextRows = nextRows.map((row) => (
    row.id === targetRowId
      ? { ...row, actions: [...row.actions, ...translatedActions] }
      : row
  ));

  // Cross-track move: update each member's `track` meta patch and clip order.
  const metaUpdates: Record<string, Partial<TimelineData['meta'][string]>> = {};
  let nextClipOrder = current.clipOrder;
  if (sourceTrackId !== targetRowId) {
    for (const clipId of group.clipIds) {
      metaUpdates[clipId] = { track: targetRowId };
      nextClipOrder = moveClipBetweenTracks(nextClipOrder, clipId, sourceTrackId, targetRowId);
    }
  }

  // Soft-tag override: trackId updated, clipIds re-derived from the translated
  // positions (order preserved for the trivial same-delta case, but reads from
  // nextRows so any future resolveOverlaps shuffles are honored).
  const orderedClipIds = orderClipIdsByAt(group.clipIds, { rows: nextRows });
  const pinnedShotGroupsOverride = (current.config.pinnedShotGroups ?? []).map((g) => (
    g.shotId === group.shotId && g.trackId === group.trackId
      ? { ...g, trackId: targetRowId, clipIds: orderedClipIds }
      : g
  ));

  return { nextRows, metaUpdates, nextClipOrder, pinnedShotGroupsOverride };
}

export function useTimelineTrackManagement({
  dataRef,
  resolvedConfig,
  selectedClipId,
  setSelectedTrackId,
  applyEdit,
}: UseTimelineTrackManagementArgs): UseTimelineTrackManagementResult {
  const moveClipToRow = useCallback((
    clipId: string,
    targetRowId: string,
    newStartTime?: number,
    transactionId?: string,
  ) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    const enclosingGroup = findEnclosingPinnedGroup(current.config, clipId);
    if (enclosingGroup) {
      const sourceTrack = current.tracks.find((track) => track.id === enclosingGroup.group.trackId);
      const targetTrack = current.tracks.find((track) => track.id === targetRowId);
      if (!sourceTrack || !targetTrack || sourceTrack.kind !== targetTrack.kind) {
        return;
      }

      const nextConfig = moveGroup(
        current.config,
        enclosingGroup.groupKey,
        typeof newStartTime === 'number' ? Math.max(0, newStartTime) : (enclosingGroup.group.start ?? 0),
        targetRowId,
      );
      applyEdit({
        type: 'pinnedShotGroups',
        pinnedShotGroups: nextConfig.pinnedShotGroups ?? [],
      }, { transactionId });
      return;
    }

    const sourceRow = current.rows.find((row) => row.actions.some((action) => action.id === clipId));
    const targetRow = current.rows.find((row) => row.id === targetRowId);
    if (!sourceRow || !targetRow) {
      return;
    }

    const sourceTrack = current.tracks.find((track) => track.id === sourceRow.id);
    const targetTrack = current.tracks.find((track) => track.id === targetRow.id);
    const action = sourceRow.actions.find((candidate) => candidate.id === clipId);
    if (!sourceTrack || !targetTrack || !action || sourceTrack.kind !== targetTrack.kind) {
      return;
    }

    const duration = action.end - action.start;
    const nextStart = typeof newStartTime === 'number' ? Math.max(0, newStartTime) : action.start;
    const nextAction = { ...action, start: nextStart, end: nextStart + duration };
    const placedRows = current.rows.map((row) => {
      if (sourceRow.id === targetRow.id && row.id === sourceRow.id) {
        return {
          ...row,
          actions: row.actions.map((candidate) => (candidate.id === clipId ? nextAction : candidate)),
        };
      }

      if (row.id === sourceRow.id) {
        return { ...row, actions: row.actions.filter((candidate) => candidate.id !== clipId) };
      }

      if (row.id === targetRow.id) {
        return { ...row, actions: [...row.actions, nextAction] };
      }

      return row;
    });

    // Trim the moved clip if it overlaps existing siblings
    const { rows: resolvedRows, metaPatches, adjustments: _adjustments } = resolveOverlaps(
      placedRows, targetRow.id, clipId, current.meta,
    );
    const nextMetaUpdates = {
      ...metaPatches,
      [clipId]: {
        track: targetRow.id,
        ...metaPatches[clipId],
      },
    };
    const nextClipOrder = moveClipBetweenTracks(current.clipOrder, clipId, sourceRow.id, targetRow.id);
    applyEdit({
      type: 'rows',
      rows: resolvedRows,
      metaUpdates: nextMetaUpdates,
      clipOrderOverride: nextClipOrder,
    }, { transactionId });
  }, [applyEdit, dataRef]);

  const createTrackAndMoveClip = useCallback((clipId: string, kind: TrackKind, newStartTime?: number, insertAtTop = false) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    const enclosingGroup = findEnclosingPinnedGroup(current.config, clipId);
    const sourceClip = current.resolvedConfig.clips.find((clip) => clip.id === clipId);
    const sourceTrackId = enclosingGroup?.group.trackId ?? sourceClip?.track;
    const sourceTrack = sourceTrackId
      ? current.resolvedConfig.tracks.find((track) => track.id === sourceTrackId)
      : null;
    if ((!sourceClip && !enclosingGroup) || !sourceTrack || sourceTrack.kind !== kind) {
      return;
    }

    const nextResolvedConfigBase = addTrack(current.resolvedConfig, kind, insertAtTop ? 0 : undefined);
    const newTrack = nextResolvedConfigBase.tracks.find((track) => {
      return !current.resolvedConfig.tracks.some((existingTrack) => existingTrack.id === track.id);
    }) ?? nextResolvedConfigBase.tracks[nextResolvedConfigBase.tracks.length - 1];
    if (!newTrack) {
      return;
    }

    if (enclosingGroup) {
      const nextConfig = moveGroup(
        {
          ...current.config,
          tracks: nextResolvedConfigBase.tracks.map((track) => ({ ...track })),
        },
        enclosingGroup.groupKey,
        typeof newStartTime === 'number' ? Math.max(0, newStartTime) : (enclosingGroup.group.start ?? 0),
        newTrack.id,
      );

      applyEdit({
        type: 'config',
        resolvedConfig: nextResolvedConfigBase,
        pinnedShotGroupsOverride: nextConfig.pinnedShotGroups,
      }, {
        selectedClipId: clipId,
        selectedTrackId: newTrack.id,
      });
      return;
    }

    const nextResolvedConfig = {
      ...nextResolvedConfigBase,
      clips: nextResolvedConfigBase.clips.map((clip) => {
        if (clip.id !== clipId) {
          return clip;
        }

        return {
          ...clip,
          at: typeof newStartTime === 'number' ? Math.max(0, newStartTime) : clip.at,
          track: newTrack.id,
        };
      }),
    };

    applyEdit({
      type: 'config',
      resolvedConfig: nextResolvedConfig,
    }, {
      selectedClipId: clipId,
      selectedTrackId: newTrack.id,
    });
  }, [applyEdit, dataRef]);

  const moveSelectedClipToTrack = useCallback((direction: 'up' | 'down') => {
    const current = dataRef.current;
    if (!current || !selectedClipId) {
      return;
    }

    const currentRowIndex = current.rows.findIndex((row) => row.actions.some((action) => action.id === selectedClipId));
    if (currentRowIndex < 0) {
      return;
    }

    const sourceTrack = current.tracks.find((track) => track.id === current.rows[currentRowIndex]?.id);
    if (!sourceTrack) {
      return;
    }

    let targetRowIndex = currentRowIndex;
    while (true) {
      targetRowIndex += direction === 'up' ? -1 : 1;
      if (targetRowIndex < 0 || targetRowIndex >= current.rows.length) {
        return;
      }

      const targetTrack = current.tracks.find((track) => track.id === current.rows[targetRowIndex]?.id);
      if (targetTrack?.kind === sourceTrack.kind) {
        moveClipToRow(selectedClipId, targetTrack.id);
        setSelectedTrackId(targetTrack.id);
        return;
      }
    }
  }, [dataRef, moveClipToRow, selectedClipId, setSelectedTrackId]);

  const moveSelectedClipsToTrack = useCallback((
    direction: 'up' | 'down',
    selectedClipIds: ReadonlySet<string>,
  ) => {
    const current = dataRef.current;
    if (!current || selectedClipIds.size === 0) {
      return;
    }

    const trackById = new Map(current.tracks.map((track) => [track.id, track]));
    const selection = categorizeSelection([...selectedClipIds], current.config);
    const freeClipIdSet = new Set(selection.freeClipIds);
    const groupsByRow = new Map<string, { clipIds: string[]; rowIndex: number; kind: TrackKind }>();
    const groupedUnits = selection.groups.flatMap((groupEntry) => {
      const group = current.config.pinnedShotGroups?.find((candidate) => (
        candidate.shotId === groupEntry.groupKey.shotId
        && candidate.trackId === groupEntry.groupKey.trackId
      ));
      if (!group) {
        return [];
      }

      const rowIndex = current.rows.findIndex((row) => row.id === group.trackId);
      const track = trackById.get(group.trackId);
      if (rowIndex < 0 || !track) {
        return [];
      }

      return [{
        kind: 'group' as const,
        groupKey: groupEntry.groupKey,
        rowIndex,
        rowId: group.trackId,
        trackKind: track.kind,
      }];
    });

    current.rows.forEach((row, rowIndex) => {
      const sourceTrack = trackById.get(row.id);
      if (!sourceTrack) {
        return;
      }

      const rowClipIds = row.actions
        .map((action) => action.id)
        .filter((clipId) => freeClipIdSet.has(clipId));
      if (rowClipIds.length === 0) {
        return;
      }

      groupsByRow.set(row.id, {
        clipIds: rowClipIds,
        rowIndex,
        kind: sourceTrack.kind,
      });
    });

    if (groupsByRow.size === 0 && groupedUnits.length === 0) {
      return;
    }

    const freeUnits = [...groupsByRow.entries()].map(([rowId, group]) => ({
      kind: 'free' as const,
      rowId,
      rowIndex: group.rowIndex,
      trackKind: group.kind,
      clipIds: group.clipIds,
    }));
    const plannedClipMoves: Array<{ clipId: string; targetRowId: string }> = [];
    const plannedGroupMoves: Array<{ groupKey: PinnedGroupKey; targetRowId: string }> = [];

    for (const kind of ['visual', 'audio'] as const) {
      const kindUnits = [
        ...freeUnits.filter((unit) => unit.trackKind === kind),
        ...groupedUnits.filter((unit) => unit.trackKind === kind),
      ];
      if (kindUnits.length === 0) {
        continue;
      }

      const kindClipMoves: Array<{ clipId: string; targetRowId: string }> = [];
      const kindGroupMoves: Array<{ groupKey: PinnedGroupKey; targetRowId: string }> = [];
      let isBlocked = false;

      for (const unit of kindUnits) {
        let targetRowIndex = unit.rowIndex;
        let targetRowId: string | null = null;

        while (true) {
          targetRowIndex += direction === 'up' ? -1 : 1;
          if (targetRowIndex < 0 || targetRowIndex >= current.rows.length) {
            isBlocked = true;
            break;
          }

          const targetTrack = trackById.get(current.rows[targetRowIndex]?.id ?? '');
          if (targetTrack?.kind === kind) {
            targetRowId = targetTrack.id;
            break;
          }
        }

        if (isBlocked || !targetRowId) {
          isBlocked = true;
          break;
        }

        if (unit.kind === 'group') {
          kindGroupMoves.push({ groupKey: unit.groupKey, targetRowId });
          continue;
        }

        for (const clipId of unit.clipIds) {
          kindClipMoves.push({ clipId, targetRowId });
        }
      }

      if (!isBlocked) {
        plannedClipMoves.push(...kindClipMoves);
        plannedGroupMoves.push(...kindGroupMoves);
      }
    }

    if (plannedClipMoves.length === 0 && plannedGroupMoves.length === 0) {
      return;
    }

    const transactionId = crypto.randomUUID();
    if (plannedGroupMoves.length > 0) {
      let nextConfig = current.config;
      for (const move of plannedGroupMoves) {
        const existingGroup = nextConfig.pinnedShotGroups?.find((group) => (
          group.shotId === move.groupKey.shotId
          && group.trackId === move.groupKey.trackId
        ));
        if (!existingGroup) {
          continue;
        }

        nextConfig = moveGroup(nextConfig, move.groupKey, existingGroup.start ?? 0, move.targetRowId);
      }

      const nextPinnedShotGroups = nextConfig.pinnedShotGroups ?? [];
      applyEdit({
        type: 'pinnedShotGroups',
        pinnedShotGroups: nextPinnedShotGroups,
      }, { transactionId });
    }

    for (const move of plannedClipMoves) {
      moveClipToRow(move.clipId, move.targetRowId, undefined, transactionId);
    }

    const primaryGroupMove = selectedClipId
      ? findEnclosingPinnedGroup(current.config, selectedClipId)
      : null;
    const primaryMove = primaryGroupMove
      ? plannedGroupMoves.find((move) => (
          move.groupKey.shotId === primaryGroupMove.groupKey.shotId
          && move.groupKey.trackId === primaryGroupMove.groupKey.trackId
        ))
      : (selectedClipId
          ? plannedClipMoves.find((move) => move.clipId === selectedClipId)
          : undefined)
        ?? plannedGroupMoves[0]
        ?? plannedClipMoves[0];
    if (primaryMove) {
      setSelectedTrackId(primaryMove.targetRowId);
    }
  }, [applyEdit, dataRef, moveClipToRow, selectedClipId, setSelectedTrackId]);

  const handleAddTrack = useCallback((kind: TrackKind) => {
    if (!resolvedConfig) {
      return;
    }

    const nextResolvedConfig = addTrack(resolvedConfig, kind);
    const nextTrack = nextResolvedConfig.tracks[nextResolvedConfig.tracks.length - 1] ?? null;
    applyEdit({ type: 'config', resolvedConfig: nextResolvedConfig }, { selectedTrackId: nextTrack?.id ?? null });
  }, [applyEdit, resolvedConfig]);

  const handleTrackPopoverChange = useCallback((trackId: string, patch: Partial<TrackDefinition>) => {
    if (!resolvedConfig) {
      return;
    }

    const nextConfig = {
      ...resolvedConfig,
      tracks: resolvedConfig.tracks.map((track) => (track.id === trackId ? { ...track, ...patch } : track)),
    };
    applyEdit({ type: 'config', resolvedConfig: nextConfig }, { selectedTrackId: trackId });
  }, [applyEdit, resolvedConfig]);

  const handleMoveTrack = useCallback((activeId: string, overId: string) => {
    if (!resolvedConfig) {
      return;
    }

    const nextTracks = moveTrackWithinKind(resolvedConfig.tracks, activeId, overId);
    if (nextTracks === resolvedConfig.tracks) {
      return;
    }

    applyEdit({ type: 'config', resolvedConfig: { ...resolvedConfig, tracks: nextTracks } }, { selectedTrackId: activeId });
  }, [applyEdit, resolvedConfig]);

  const handleRemoveTrack = useCallback((trackId: string) => {
    if (!resolvedConfig) {
      return;
    }

    const track = resolvedConfig.tracks.find((entry) => entry.id === trackId);
    if (!track) {
      return;
    }

    const sameKind = resolvedConfig.tracks.filter((entry) => entry.kind === track.kind);
    if (sameKind.length <= 1) {
      return;
    }

    const nextConfig = {
      ...resolvedConfig,
      tracks: resolvedConfig.tracks.filter((entry) => entry.id !== trackId),
      clips: resolvedConfig.clips.filter((clip) => clip.track !== trackId),
    };
    applyEdit({ type: 'config', resolvedConfig: nextConfig }, { selectedTrackId: null, semantic: true });
  }, [applyEdit, resolvedConfig]);

  const unusedTrackCount = useMemo(() => {
    if (!resolvedConfig) {
      return 0;
    }

    const tracksWithClips = new Set(resolvedConfig.clips.map((clip) => clip.track));
    const defaultTrackIds = new Set(DEFAULT_VIDEO_TRACKS.map((track) => track.id));

    // Count how many tracks would actually be removed (matching handleClearUnusedTracks logic).
    // We always keep at least one track per kind, even if it's empty.
    let keptEmptyVisual = false;
    let keptEmptyAudio = false;
    let removable = 0;

    for (const track of resolvedConfig.tracks) {
      if (defaultTrackIds.has(track.id) || tracksWithClips.has(track.id)) {
        continue;
      }

      if (track.kind === 'visual' && !keptEmptyVisual) {
        const hasVisualWithClips = resolvedConfig.tracks.some((t) => t.kind === 'visual' && tracksWithClips.has(t.id));
        if (!hasVisualWithClips) {
          keptEmptyVisual = true;
          continue;
        }
      }

      if (track.kind === 'audio' && !keptEmptyAudio) {
        const hasAudioWithClips = resolvedConfig.tracks.some((t) => t.kind === 'audio' && tracksWithClips.has(t.id));
        if (!hasAudioWithClips) {
          keptEmptyAudio = true;
          continue;
        }
      }

      removable++;
    }

    return removable;
  }, [resolvedConfig]);

  const handleClearUnusedTracks = useCallback(() => {
    if (!resolvedConfig || unusedTrackCount === 0) {
      return;
    }

    const tracksWithClips = new Set(resolvedConfig.clips.map((clip) => clip.track));
    const defaultTrackIds = new Set(DEFAULT_VIDEO_TRACKS.map((track) => track.id));
    const visualWithClips = resolvedConfig.tracks.filter((track) => track.kind === 'visual' && tracksWithClips.has(track.id));
    const audioWithClips = resolvedConfig.tracks.filter((track) => track.kind === 'audio' && tracksWithClips.has(track.id));

    const nextTracks = resolvedConfig.tracks.filter((track) => {
      if (defaultTrackIds.has(track.id)) {
        return true;
      }

      if (tracksWithClips.has(track.id)) {
        return true;
      }

      if (track.kind === 'visual' && visualWithClips.length === 0) {
        visualWithClips.push(track);
        return true;
      }

      if (track.kind === 'audio' && audioWithClips.length === 0) {
        audioWithClips.push(track);
        return true;
      }

      return false;
    });

    applyEdit({ type: 'config', resolvedConfig: { ...resolvedConfig, tracks: nextTracks } }, { selectedTrackId: null, semantic: true });
  }, [applyEdit, resolvedConfig, unusedTrackCount]);

  return {
    handleAddTrack,
    handleTrackPopoverChange,
    handleMoveTrack,
    handleRemoveTrack,
    handleClearUnusedTracks,
    unusedTrackCount,
    moveClipToRow,
    createTrackAndMoveClip,
    moveSelectedClipToTrack,
    moveSelectedClipsToTrack,
  };
}

import { useCallback } from 'react';
import { generateUUID } from '@/shared/lib/taskCreation/ids';
import { updateClipOrder } from '@/tools/video-editor/lib/coordinate-utils';
import { getNextClipId, type ClipMeta } from '@/tools/video-editor/lib/timeline-data';
import {
  buildGroupFromChildren,
  replaceGroupChildren,
} from '@/tools/video-editor/lib/pinned-group-projection';
import type {
  TimelineApplyEdit,
  TimelineDataRef,
  TimelinePatchRegistry,
  TimelineRegisterAsset,
} from '@/tools/video-editor/hooks/timeline-state-types';
import type { ShotFinalVideo } from '@/tools/video-editor/hooks/useFinalVideoAvailable';
import type { AssetRegistryEntry, PinnedShotGroup, PinnedShotImageClipSnapshot, TimelineConfig } from '@/tools/video-editor/types';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';

interface UseSwitchToFinalVideoArgs {
  applyEdit: TimelineApplyEdit;
  dataRef: TimelineDataRef;
  finalVideoMap: Map<string, ShotFinalVideo>;
  patchRegistry: TimelinePatchRegistry;
  registerAsset: TimelineRegisterAsset;
}

function getClipDuration(meta: ClipMeta, action: TimelineAction): number {
  if (typeof meta.hold === 'number' && Number.isFinite(meta.hold) && meta.hold > 0) {
    return meta.hold;
  }

  if (
    typeof meta.from === 'number'
    && typeof meta.to === 'number'
    && Number.isFinite(meta.from)
    && Number.isFinite(meta.to)
    && meta.to > meta.from
  ) {
    return Math.max(0.05, (meta.to - meta.from) / Math.max(meta.speed ?? 1, 0.01));
  }

  return Math.max(0.05, action.end - action.start);
}

function snapshotClipMeta(meta: ClipMeta): PinnedShotImageClipSnapshot['meta'] {
  return {
    clipType: meta.clipType,
    from: meta.from,
    to: meta.to,
    speed: meta.speed,
    hold: meta.hold,
    volume: meta.volume,
    x: meta.x,
    y: meta.y,
    width: meta.width,
    height: meta.height,
    cropTop: meta.cropTop,
    cropBottom: meta.cropBottom,
    cropLeft: meta.cropLeft,
    cropRight: meta.cropRight,
    opacity: meta.opacity,
    text: meta.text,
    entrance: meta.entrance,
    exit: meta.exit,
    continuous: meta.continuous,
    transition: meta.transition,
    effects: meta.effects,
  };
}

function updatePinnedGroupWithChildren({
  config,
  shotId,
  trackId,
  start,
  nextChildren,
  mode,
  videoAssetKey,
  imageClipSnapshot,
}: {
  config: Pick<TimelineConfig, 'output' | 'clips' | 'pinnedShotGroups'>;
  shotId: string;
  trackId: string;
  start: number;
  nextChildren: NonNullable<PinnedShotGroup['children']>;
  mode: PinnedShotGroup['mode'];
  videoAssetKey?: string;
  imageClipSnapshot?: PinnedShotGroup['imageClipSnapshot'];
}) {
  const pinnedShotGroups = config.pinnedShotGroups ?? [];
  const groupKey = { shotId, trackId };
  const hasExistingGroup = pinnedShotGroups.some((group) => (
    group.shotId === shotId
    && group.trackId === trackId
  ));
  const nextGroups = hasExistingGroup
    ? (replaceGroupChildren(
        {
          ...config,
          pinnedShotGroups,
        },
        groupKey,
        nextChildren,
      ).pinnedShotGroups ?? [])
    : [
        ...pinnedShotGroups,
        buildGroupFromChildren({
          shotId,
          trackId,
          start,
          children: nextChildren,
          mode,
          videoAssetKey,
          imageClipSnapshot,
        }),
      ];

  return nextGroups.map((group) => {
    if (group.shotId !== shotId || group.trackId !== trackId) {
      return group;
    }

    return {
      ...group,
      mode,
      videoAssetKey,
      imageClipSnapshot,
    };
  });
}

function registerFinalVideoAsset(
  finalVideo: ShotFinalVideo,
  patchRegistry: TimelinePatchRegistry,
  registerAsset: TimelineRegisterAsset,
): string {
  const assetKey = generateUUID();
  const assetEntry: AssetRegistryEntry = {
    file: finalVideo.location,
    type: 'video/mp4',
    generationId: finalVideo.id,
  };
  patchRegistry(assetKey, assetEntry, finalVideo.location);
  void registerAsset(assetKey, assetEntry).catch((error) => {
    console.error('[TimelineEditor] Failed to persist final video asset:', error);
  });
  return assetKey;
}

export function useSwitchToFinalVideo({
  applyEdit,
  dataRef,
  finalVideoMap,
  patchRegistry,
  registerAsset,
}: UseSwitchToFinalVideoArgs) {
  const switchToFinalVideo = useCallback(({ shotId, clipIds, rowId }: { shotId: string; clipIds: string[]; rowId: string }) => {
    const finalVideo = finalVideoMap.get(shotId);
    const current = dataRef.current;
    if (!finalVideo || !current || clipIds.length === 0 || !current.rows.some((row) => row.id === rowId)) {
      return;
    }

    const existingPinnedGroups = current.config.pinnedShotGroups ?? [];
    const pinnedGroup = existingPinnedGroups.find((group) => group.shotId === shotId && group.trackId === rowId);
    const sourceClipIds = pinnedGroup?.mode === 'images'
      ? pinnedGroup.clipIds
      : clipIds;
    const clipIdSet = new Set(sourceClipIds);
    const targetRow = current.rows.find((row) => row.id === rowId);
    if (!targetRow) {
      return;
    }

    const imageActions = targetRow.actions.filter((action) => clipIdSet.has(action.id));
    if (imageActions.length !== sourceClipIds.length) {
      return;
    }

    const startTime = Math.min(...imageActions.map((action) => action.start));
    const endTime = Math.max(...imageActions.map((action) => action.end));
    if (!Number.isFinite(startTime) || !Number.isFinite(endTime) || endTime <= startTime) {
      return;
    }
    const groupStart = pinnedGroup?.start ?? startTime;

    const imageClipSnapshot = sourceClipIds.flatMap((sourceClipId) => {
      const sourceMeta = current.meta[sourceClipId];
      if (!sourceMeta) {
        return [];
      }

      return [{
        clipId: sourceClipId,
        assetKey: sourceMeta.asset,
        meta: snapshotClipMeta(sourceMeta),
      }];
    });
    if (imageClipSnapshot.length !== sourceClipIds.length) {
      return;
    }

    const assetKey = registerFinalVideoAsset(finalVideo, patchRegistry, registerAsset);

    const videoClipId = getNextClipId(current.meta);
    const targetTrack = current.tracks.find((track) => track.id === rowId);
    const isManualVisualTrack = targetTrack?.kind === 'visual' && targetTrack.fit === 'manual';
    const videoMeta: ClipMeta = {
      asset: assetKey,
      track: rowId,
      clipType: 'media',
      from: 0,
      to: endTime - startTime,
      speed: 1,
      volume: 1,
      opacity: 1,
      x: isManualVisualTrack ? 100 : undefined,
      y: isManualVisualTrack ? 100 : undefined,
      width: isManualVisualTrack ? 320 : undefined,
      height: isManualVisualTrack ? 240 : undefined,
    };
    const videoAction: TimelineAction = {
      id: videoClipId,
      start: groupStart,
      end: groupStart + (endTime - startTime),
      effectId: `effect-${videoClipId}`,
    };

    const insertionIndex = targetRow.actions.findIndex((action) => clipIdSet.has(action.id));
    const nextRows = current.rows.map((row) => {
      const remainingActions = row.actions.filter((action) => !clipIdSet.has(action.id));
      if (row.id !== rowId) {
        return remainingActions.length === row.actions.length ? row : { ...row, actions: remainingActions };
      }

      const nextActions = insertionIndex < 0
        ? [...remainingActions, videoAction]
        : [...remainingActions.slice(0, insertionIndex), videoAction, ...remainingActions.slice(insertionIndex)];
      return { ...row, actions: nextActions };
    });
    const nextClipOrder = updateClipOrder(current.clipOrder, rowId, (ids) => {
      const filtered = ids.filter((id) => !clipIdSet.has(id));
      const orderInsertionIndex = ids.findIndex((id) => clipIdSet.has(id));
      return orderInsertionIndex < 0
        ? [...filtered, videoClipId]
        : [...filtered.slice(0, orderInsertionIndex), videoClipId, ...filtered.slice(orderInsertionIndex)];
    });

    const nextPinnedShotGroups = updatePinnedGroupWithChildren({
      config: current.config,
      shotId,
      trackId: rowId,
      start: groupStart,
      nextChildren: [{
        clipId: videoClipId,
        offset: 0,
        duration: videoAction.end - videoAction.start,
      }],
      mode: 'video',
      videoAssetKey: assetKey,
      imageClipSnapshot,
    });

    applyEdit({
      type: 'rows',
      rows: nextRows,
      metaUpdates: { [videoClipId]: videoMeta },
      metaDeletes: sourceClipIds,
      clipOrderOverride: nextClipOrder,
      pinnedShotGroupsOverride: nextPinnedShotGroups,
    });
  }, [applyEdit, dataRef, finalVideoMap, patchRegistry, registerAsset]);

  const updateToLatestVideo = useCallback(({ shotId, rowId }: { shotId: string; rowId: string }) => {
    const current = dataRef.current;
    const finalVideo = finalVideoMap.get(shotId);
    if (!current || !finalVideo) {
      return;
    }

    const existingPinnedGroups = current.config.pinnedShotGroups ?? [];
    const pinnedGroup = existingPinnedGroups.find((group) => (
      group.shotId === shotId
      && group.trackId === rowId
      && group.mode === 'video'
      && typeof group.videoAssetKey === 'string'
      && group.videoAssetKey.length > 0
    ));
    const videoClipId = pinnedGroup?.clipIds[0];
    const targetRow = current.rows.find((row) => row.id === rowId);
    const videoAction = videoClipId ? targetRow?.actions.find((action) => action.id === videoClipId) : undefined;
    const videoMeta = videoClipId ? current.meta[videoClipId] : undefined;
    const currentGenerationId = pinnedGroup?.videoAssetKey
      ? current.registry.assets[pinnedGroup.videoAssetKey]?.generationId
      : undefined;
    if (!pinnedGroup || !videoClipId || !videoAction || !videoMeta || currentGenerationId === finalVideo.id) {
      return;
    }

    const assetKey = registerFinalVideoAsset(finalVideo, patchRegistry, registerAsset);
    const nextPinnedShotGroups = existingPinnedGroups.map((group) => (
      group.shotId === shotId && group.trackId === rowId
        ? { ...group, videoAssetKey: assetKey }
        : group
    ));

    applyEdit({
      type: 'rows',
      rows: current.rows,
      metaUpdates: {
        [videoClipId]: {
          asset: assetKey,
        },
      },
      pinnedShotGroupsOverride: nextPinnedShotGroups,
    });
  }, [applyEdit, dataRef, finalVideoMap, patchRegistry, registerAsset]);

  const switchToImages = useCallback(({ shotId, rowId }: { shotId: string; rowId: string }) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    const existingPinnedGroups = current.config.pinnedShotGroups ?? [];
    const pinnedGroup = existingPinnedGroups.find((group) => (
      group.shotId === shotId
      && group.trackId === rowId
      && group.mode === 'video'
    ));
    const targetRow = current.rows.find((row) => row.id === rowId);
    const videoClipId = pinnedGroup?.clipIds[0];
    const videoActionIndex = targetRow?.actions.findIndex((action) => action.id === videoClipId) ?? -1;
    const videoAction = videoActionIndex >= 0 ? targetRow?.actions[videoActionIndex] : undefined;
    if (!pinnedGroup || !targetRow || !videoClipId || !videoAction || !pinnedGroup.imageClipSnapshot?.length) {
      return;
    }

    const restoredMetaUpdates: Record<string, ClipMeta> = {};
    let cursor = 0;
    const restoredChildren = pinnedGroup.imageClipSnapshot.map((snapshot) => {
      const clipMeta: ClipMeta = {
        ...snapshot.meta,
        asset: snapshot.assetKey,
        track: rowId,
      };
      restoredMetaUpdates[snapshot.clipId] = clipMeta;
      const duration = getClipDuration(clipMeta, videoAction);
      const child = {
        clipId: snapshot.clipId,
        offset: cursor,
        duration,
      };
      cursor += duration;
      return child;
    });
    const nextPinnedShotGroups = updatePinnedGroupWithChildren({
      config: current.config,
      shotId,
      trackId: rowId,
      start: pinnedGroup.start ?? 0,
      nextChildren: restoredChildren,
      mode: 'images',
      imageClipSnapshot: pinnedGroup.imageClipSnapshot,
    });
    const nextPinnedGroup = nextPinnedShotGroups.find((group) => (
      group.shotId === shotId
      && group.trackId === rowId
    ));
    if (!nextPinnedGroup) {
      return;
    }
    const groupStart = nextPinnedGroup.start ?? 0;
    const restoredActions = (nextPinnedGroup.children ?? []).map((child) => ({
      id: child.clipId,
      start: groupStart + child.offset,
      end: groupStart + child.offset + child.duration,
      effectId: `effect-${child.clipId}`,
    }));

    const nextRows = current.rows.map((row) => {
      if (row.id !== rowId) {
        return row;
      }

      const remainingActions = row.actions.filter((action) => action.id !== videoClipId);
      return {
        ...row,
        actions: [
          ...remainingActions.slice(0, videoActionIndex),
          ...restoredActions,
          ...remainingActions.slice(videoActionIndex),
        ],
      };
    });
    const nextClipOrder = updateClipOrder(current.clipOrder, rowId, (ids) => {
      const filtered = ids.filter((id) => id !== videoClipId);
      const insertionIndex = ids.indexOf(videoClipId);
      const restoredClipIds = pinnedGroup.imageClipSnapshot?.map((snapshot) => snapshot.clipId) ?? [];
      return insertionIndex < 0
        ? [...filtered, ...restoredClipIds]
        : [...filtered.slice(0, insertionIndex), ...restoredClipIds, ...filtered.slice(insertionIndex)];
    });

    applyEdit({
      type: 'rows',
      rows: nextRows,
      metaUpdates: restoredMetaUpdates,
      metaDeletes: [videoClipId],
      clipOrderOverride: nextClipOrder,
      pinnedShotGroupsOverride: nextPinnedShotGroups,
    });
  }, [applyEdit, dataRef]);

  return {
    switchToFinalVideo,
    updateToLatestVideo,
    switchToImages,
  };
}

// @vitest-environment jsdom
import { renderHook } from '@testing-library/react';
import { describe, expect, it } from 'vitest';
import type { Shot } from '@/domains/generation/types';
import { buildGroupFromChildren } from '@/tools/video-editor/lib/pinned-group-projection';
import type { TimelineAction, TimelineRow } from '@/tools/video-editor/types/timeline-canvas';
import { getShotColor, useShotGroups } from './useShotGroups';

function buildAction(id: string, start: number, end: number): TimelineAction {
  return { id, start, end, effectId: `effect-${id}` };
}

function buildShot(id: string, name: string): Shot {
  return { id, name, images: [] } as Shot;
}

describe('useShotGroups', () => {
  it('returns deterministic colors and different colors for distinct sample shot ids', () => {
    expect(getShotColor('shot-a')).toBe(getShotColor('shot-a'));
    expect(new Set(['shot-a', 'shot-b', 'shot-c'].map((shotId) => getShotColor(shotId))).size).toBe(3);
  });

  it('returns empty array when pinnedShotGroups is undefined', () => {
    const rows: TimelineRow[] = [{ id: 'V1', actions: [buildAction('clip-1', 0, 1)] }];
    const { result } = renderHook(() => useShotGroups(rows, [buildShot('shot-1', 'Shot 1')]));
    expect(result.current).toEqual([]);
  });

  it('returns pinned groups', () => {
    const rows: TimelineRow[] = [{ id: 'V1', actions: [buildAction('clip-1', 0, 2)] }];
    const { result } = renderHook(() => useShotGroups(
      rows,
      [buildShot('shot-1', 'Shot 1')],
      [buildGroupFromChildren({
        shotId: 'shot-1',
        trackId: 'V1',
        start: 0,
        children: [{ clipId: 'clip-1', offset: 0, duration: 2 }],
        mode: 'video',
      })],
    ));

    expect(result.current).toEqual([{
      shotId: 'shot-1',
      shotName: 'Shot 1',
      rowId: 'V1',
      rowIndex: 0,
      start: 0,
      clipIds: ['clip-1'],
      children: [{ clipId: 'clip-1', offset: 0, duration: 2 }],
      color: getShotColor('shot-1'),
      mode: 'video',
    }]);
  });

  it('filters out pinned groups whose trackId does not match any row', () => {
    const rows: TimelineRow[] = [{ id: 'V1', actions: [buildAction('clip-1', 0, 2)] }];
    const { result } = renderHook(() => useShotGroups(
      rows,
      [buildShot('shot-1', 'Shot 1')],
      [buildGroupFromChildren({
        shotId: 'shot-1',
        trackId: 'V2',
        start: 0,
        children: [{ clipId: 'clip-1', offset: 0, duration: 2 }],
        mode: 'images',
      })],
    ));
    expect(result.current).toEqual([]);
  });

  it('trusts normalized children even if the row actions are not hydrated yet', () => {
    const rows: TimelineRow[] = [{ id: 'V1', actions: [] }];
    const { result } = renderHook(() => useShotGroups(
      rows,
      [buildShot('shot-1', 'Shot 1')],
      [buildGroupFromChildren({
        shotId: 'shot-1',
        trackId: 'V1',
        start: 1,
        children: [
          { clipId: 'clip-1', offset: 0, duration: 1 },
          { clipId: 'clip-2', offset: 1, duration: 1 },
        ],
        mode: 'images',
      })],
    ));

    expect(result.current).toEqual([{
      shotId: 'shot-1',
      shotName: 'Shot 1',
      rowId: 'V1',
      rowIndex: 0,
      start: 1,
      clipIds: ['clip-1', 'clip-2'],
      children: [
        { clipId: 'clip-1', offset: 0, duration: 1 },
        { clipId: 'clip-2', offset: 1, duration: 1 },
      ],
      color: getShotColor('shot-1'),
      mode: 'images',
    }]);
  });
});

