async function dispatchTimelineDrop({
  event,
  dataRef,
  pendingOpsRef,
  dropPosition,
  selectedTrackId,
  applyEdit,
  patchRegistry,
  uploadAsset,
  invalidateAssetRegistry,
  resolveAssetUrl,
  registerGenerationAsset,
  uploadImageGeneration,
  uploadVideoGeneration,
  dropAsset,
  handleAddTextAt,
  shots,
}: {
  event: React.DragEvent<HTMLDivElement>;
  dataRef: React.MutableRefObject<TimelineData | null>;
  pendingOpsRef: React.MutableRefObject<number>;
  dropPosition: TimelineDropPosition;
  selectedTrackId: string | null;
  applyEdit: TimelineApplyEdit;
  patchRegistry: TimelinePatchRegistry;
  uploadAsset: TimelineUploadAsset;
  invalidateAssetRegistry: TimelineInvalidateAssetRegistry;
  resolveAssetUrl: (file: string) => Promise<string>;
  registerGenerationAsset: UseAssetManagementResult['registerGenerationAsset'];
  uploadImageGeneration: UseAssetManagementResult['uploadImageGeneration'];
  uploadVideoGeneration: UseAssetManagementResult['uploadVideoGeneration'];
  dropAsset: UseAssetManagementResult['handleAssetDrop'];
  handleAddTextAt?: (trackId: string, time: number) => void;
  shots: Shot[] | undefined;
}) {
  const insertAtTop = Boolean(dropPosition.isNewTrackTop);

  if (event.dataTransfer.types.includes('text-tool')) {
    handleTextToolDrop({ dataRef, dropPosition, insertAtTop, handleAddTextAt });
    return;
  }

  if (event.dataTransfer.types.includes('effect-layer')) {
    handleEffectLayerDrop({ dataRef, dropPosition, insertAtTop, selectedTrackId, applyEdit });
    return;
  }

  if (await handleFileDrop({
    files: Array.from(event.dataTransfer.files),
    dataRef,
    pendingOpsRef,
    dropPosition,
    insertAtTop,
    selectedTrackId,
    applyEdit,
    patchRegistry,
    uploadAsset,
    invalidateAssetRegistry,
    resolveAssetUrl,
    registerGenerationAsset,
    uploadImageGeneration,
    uploadVideoGeneration,
    dropAsset,
  })) {
    return;
  }

  const shotData = getShotDropData(event);
  if (shotData) {
    const shot = shots?.find((candidate) => candidate.id === shotData.shotId);
    const shotImages = shotData.imageGenerationIds
      .map((generationId) => shot?.images?.find((image) => image.generation_id === generationId))
      .filter((image): image is NonNullable<NonNullable<typeof shot>['images']>[number] => {
        return Boolean(image?.generation_id && (image.imageUrl || image.location));
      });
    const resolvedTarget = resolveAssetDropTarget({
      dataRef,
      assetKind: 'visual',
      trackId: dropPosition.isNewTrack ? undefined : dropPosition.trackId,
      selectedTrackId,
      forceNewTrack: dropPosition.isNewTrack,
      insertAtTop,
    });

    if (!shot || !resolvedTarget || shotImages.length === 0) {
      return;
    }

    let workingData = resolvedTarget.current;
    const nextPinnedShotGroups = [...(workingData.config.pinnedShotGroups ?? [])];
    const metaUpdates: Record<string, TimelineData['meta'][string]> = {};
    const children: Array<{ clipId: string; offset: number; duration: number }> = [];
    let timeOffset = 0;

    for (const shotImage of shotImages) {
      if (!shotImage.generation_id) continue;
      const assetKey = registerGenerationAsset({
        generationId: shotImage.generation_id,
        variantType: 'image',
        imageUrl: shotImage.imageUrl ?? shotImage.location ?? '',
        thumbUrl: shotImage.thumbUrl ?? (shotImage as { thumbnail_url?: string }).thumbnail_url ?? shotImage.imageUrl ?? shotImage.location ?? '',
        metadata: {
          content_type: shotImage.contentType ?? shotImage.type ?? 'image/png',
        },
      });
      if (!assetKey) {
        continue;
      }

      const nextEdit = buildAssetDropEdit({
        current: workingData,
        assetKey,
        trackId: resolvedTarget.trackId,
        time: dropPosition.time + timeOffset,
      });
      if (!nextEdit) {
        continue;
      }

      Object.assign(metaUpdates, nextEdit.metaUpdates);
      children.push({
        clipId: nextEdit.clipId,
        offset: timeOffset,
        duration: nextEdit.duration,
      });
      timeOffset += nextEdit.duration;
      workingData = {
        ...workingData,
        rows: nextEdit.rows,
        meta: {
          ...workingData.meta,
          ...nextEdit.metaUpdates,
        },
        clipOrder: nextEdit.clipOrderOverride,
      };
    }

    if (children.length === 0) {
      return;
    }

    const nextGroup = buildGroupFromChildren({
      shotId: shot.id,
      trackId: resolvedTarget.trackId,
      start: Math.max(0, dropPosition.time),
      children,
      mode: 'images',
    });
    nextPinnedShotGroups.push(nextGroup);

    applyEdit({
      type: 'rows',
      rows: workingData.rows,
      metaUpdates,
      clipOrderOverride: workingData.clipOrder,
      pinnedShotGroupsOverride: nextPinnedShotGroups,
    }, {
      selectedClipId: children[0]?.clipId ?? null,
      selectedTrackId: resolvedTarget.trackId,
    });
    return;
  }

  const multiGenerationData = getMultiGenerationDropData(event);
  if (multiGenerationData?.length) {
    handleMultiGenerationDrop({
      generationItems: multiGenerationData,
      dataRef,
      dropPosition,
      insertAtTop,
      registerGenerationAsset,
      patchRegistry,
      dropAsset,
    });
    return;
  }

  const generationData = getGenerationDropData(event);
  if (generationData) {
    handleSingleGenerationDrop({
      generationData,
      dataRef,
      dropPosition,
      insertAtTop,
      registerGenerationAsset,
      dropAsset,
    });
    return;
  }

  handleAssetDrop({
    assetKey: event.dataTransfer.getData('asset-key'),
    assetKind: event.dataTransfer.getData('asset-kind') as TrackKind,
    dataRef,
    dropPosition,
    insertAtTop,
    selectedTrackId,
    dropAsset,
  });
}

export interface UseExternalDropArgs {
  dataRef: React.MutableRefObject<TimelineData | null>;
  pendingOpsRef: React.MutableRefObject<number>;
  scale: number;
  scaleWidth: number;
  selectedTrackId: string | null;
  applyEdit: TimelineApplyEdit;
  patchRegistry: TimelinePatchRegistry;
  registerAsset: TimelineRegisterAsset;
  uploadAsset: TimelineUploadAsset;
  invalidateAssetRegistry: TimelineInvalidateAssetRegistry;
  resolveAssetUrl: (file: string) => Promise<string>;
  coordinator: DragCoordinator;
  registerGenerationAsset: UseAssetManagementResult['registerGenerationAsset'];
  uploadImageGeneration: UseAssetManagementResult['uploadImageGeneration'];
  uploadVideoGeneration: UseAssetManagementResult['uploadVideoGeneration'];
  handleAssetDrop: UseAssetManagementResult['handleAssetDrop'];
  handleAddTextAt?: (trackId: string, time: number) => void;
  onSeekToTime?: (time: number) => void;

  applyEdit({
    type: 'config',
    resolvedConfig: nextResolvedConfig,
  }, {
    selectedClipId: clipId,
    selectedTrackId: newTrack.id,
  });
}, [applyEdit, dataRef]);

const moveSelectedClipToTrack = useCallback((direction: 'up' | 'down') => {
  const current = dataRef.current;
  if (!current || !selectedClipId) {
    return;
  }

  const currentRowIndex = current.rows.findIndex((row) => row.actions.some((action) => action.id === selectedClipId));
  if (currentRowIndex < 0) {
    return;
  }

  const sourceTrack = current.tracks.find((track) => track.id === current.rows[currentRowIndex]?.id);
  if (!sourceTrack) {
    return;
  }

  let targetRowIndex = currentRowIndex;
  while (true) {
    targetRowIndex += direction === 'up' ? -1 : 1;
    if (targetRowIndex < 0 || targetRowIndex >= current.rows.length) {
      return;
    }

    const targetTrack = current.tracks.find((track) => track.id === current.rows[targetRowIndex]?.id);
    if (targetTrack?.kind === sourceTrack.kind) {
      moveClipToRow(selectedClipId, targetTrack.id);
      setSelectedTrackId(targetTrack.id);
      return;
    }
  }
}, [dataRef, moveClipToRow, selectedClipId, setSelectedTrackId]);

const moveSelectedClipsToTrack = useCallback((
  direction: 'up' | 'down',
  selectedClipIds: ReadonlySet<string>,
) => {
  const current = dataRef.current;
  if (!current || selectedClipIds.size === 0) {
    return;
  }

  const trackById = new Map(current.tracks.map((track) => [track.id, track]));
  const selection = categorizeSelection([...selectedClipIds], current.config);
  const freeClipIdSet = new Set(selection.freeClipIds);
  const groupsByRow = new Map<string, { clipIds: string[]; rowIndex: number; kind: TrackKind }>();
  const groupedUnits = selection.groups.flatMap((groupEntry) => {
    const group = current.config.pinnedShotGroups?.find((candidate) => (
      candidate.shotId === groupEntry.groupKey.shotId
      && candidate.trackId === groupEntry.groupKey.trackId
    ));
    if (!group) {
      return [];
    }

    const rowIndex = current.rows.findIndex((row) => row.id === group.trackId);
    const track = trackById.get(group.trackId);
    if (rowIndex < 0 || !track) {
      return [];
    }

    return [{
      kind: 'group' as const,
      groupKey: groupEntry.groupKey,
      rowIndex,
      rowId: group.trackId,
      trackKind: track.kind,
    }];
  });

  current.rows.forEach((row, rowIndex) => {
    const sourceTrack = trackById.get(row.id);
    if (!sourceTrack) {
      return;
    }

    const rowClipIds = row.actions
      .map((action) => action.id)
      .filter((clipId) => freeClipIdSet.has(clipId));
    if (rowClipIds.length === 0) {
      return;
    }

    groupsByRow.set(row.id, {
      clipIds: rowClipIds,
      rowIndex,
      kind: sourceTrack.kind,
    });
  });

  if (groupsByRow.size === 0 && groupedUnits.length === 0) {
    return;
  }

  const freeUnits = [...groupsByRow.entries()].map(([rowId, group]) => ({
    kind: 'free' as const,
    rowId,
    rowIndex: group.rowIndex,
    trackKind: group.kind,
    clipIds: group.clipIds,
  }));
  const plannedClipMoves: Array<{ clipId: string; targetRowId: string }> = [];
  const plannedGroupMoves: Array<{ groupKey: PinnedGroupKey; targetRowId: string }> = [];

  for (const kind of ['visual', 'audio'] as const) {
    const kindUnits = [
      ...freeUnits.filter((unit) => unit.trackKind === kind),
      ...groupedUnits.filter((unit) => unit.trackKind === kind),
    ];
    if (kindUnits.length === 0) {
      continue;
    }

    const kindClipMoves: Array<{ clipId: string; targetRowId: string }> = [];
    const kindGroupMoves: Array<{ groupKey: PinnedGroupKey; targetRowId: string }> = [];
    let isBlocked = false;

    for (const unit of kindUnits) {
      let targetRowIndex = unit.rowIndex;
      let targetRowId: string | null = null;

      while (true) {
        targetRowIndex += direction === 'up' ? -1 : 1;
        if (targetRowIndex < 0 || targetRowIndex >= current.rows.length) {
          isBlocked = true;
          break;
        }

        const targetTrack = trackById.get(current.rows[targetRowIndex]?.id ?? '');
        if (targetTrack?.kind === kind) {
          targetRowId = targetTrack.id;
          break;
        }
      }

      if (isBlocked || !targetRowId) {
        isBlocked = true;
        break;
      }

      if (unit.kind === 'group') {
        kindGroupMoves.push({ groupKey: unit.groupKey, targetRowId });
        continue;
      }

      for (const clipId of unit.clipIds) {
        kindClipMoves.push({ clipId, targetRowId });
      }
    }

    if (!isBlocked) {
      plannedClipMoves.push(...kindClipMoves);
      plannedGroupMoves.push(...kindGroupMoves);
    }
  }

  if (plannedClipMoves.length === 0 && plannedGroupMoves.length === 0) {
    return;
  }

  const transactionId = crypto.randomUUID();
  if (plannedGroupMoves.length > 0) {
    let nextConfig = current.config;
    for (const move of plannedGroupMoves) {
      const existingGroup = nextConfig.pinnedShotGroups?.find((group) => (
        group.shotId === move.groupKey.shotId
        && group.trackId === move.groupKey.trackId
      ));
      if (!existingGroup) {
        continue;
      }

      nextConfig = moveGroup(nextConfig, move.groupKey, existingGroup.start ?? 0, move.targetRowId);
    }

    const nextPinnedShotGroups = nextConfig.pinnedShotGroups ?? [];
    applyEdit({
      type: 'pinnedShotGroups',
      pinnedShotGroups: nextPinnedShotGroups,
    }, { transactionId });
  }

  for (const move of plannedClipMoves) {
    moveClipToRow(move.clipId, move.targetRowId, undefined, transactionId);
  }

  const primaryGroupMove = selectedClipId
    ? findEnclosingPinnedGroup(current.config, selectedClipId)
    : null;
  const primaryMove = primaryGroupMove
    ? plannedGroupMoves.find((move) => (
        move.groupKey.shotId === primaryGroupMove.groupKey.shotId

        move.groupKey.shotId === primaryGroupMove.groupKey.shotId
        && move.groupKey.trackId === primaryGroupMove.groupKey.trackId
      ))
    : (selectedClipId
        ? plannedClipMoves.find((move) => move.clipId === selectedClipId)
        : undefined)
      ?? plannedGroupMoves[0]
      ?? plannedClipMoves[0];
  if (primaryMove) {
    setSelectedTrackId(primaryMove.targetRowId);
  }
}, [applyEdit, dataRef, moveClipToRow, selectedClipId, setSelectedTrackId]);

const handleAddTrack = useCallback((kind: TrackKind) => {
  if (!resolvedConfig) {
    return;
  }

  const nextResolvedConfig = addTrack(resolvedConfig, kind);
  const nextTrack = nextResolvedConfig.tracks[nextResolvedConfig.tracks.length - 1] ?? null;
  applyEdit({ type: 'config', resolvedConfig: nextResolvedConfig }, { selectedTrackId: nextTrack?.id ?? null });
}, [applyEdit, resolvedConfig]);

const handleTrackPopoverChange = useCallback((trackId: string, patch: Partial<TrackDefinition>) => {
  if (!resolvedConfig) {
    return;
  }

  const nextConfig = {
    ...resolvedConfig,
    tracks: resolvedConfig.tracks.map((track) => (track.id === trackId ? { ...track, ...patch } : track)),
  };
  applyEdit({ type: 'config', resolvedConfig: nextConfig }, { selectedTrackId: trackId });
}, [applyEdit, resolvedConfig]);

const handleMoveTrack = useCallback((activeId: string, overId: string) => {
  if (!resolvedConfig) {
    return;
  }

  const nextTracks = moveTrackWithinKind(resolvedConfig.tracks, activeId, overId);
  if (nextTracks === resolvedConfig.tracks) {
    return;
  }

  applyEdit({ type: 'config', resolvedConfig: { ...resolvedConfig, tracks: nextTracks } }, { selectedTrackId: activeId });
}, [applyEdit, resolvedConfig]);

const handleRemoveTrack = useCallback((trackId: string) => {
  if (!resolvedConfig) {
    return;
  }

  const track = resolvedConfig.tracks.find((entry) => entry.id === trackId);
  if (!track) {
    return;
  }

  const sameKind = resolvedConfig.tracks.filter((entry) => entry.kind === track.kind);
  if (sameKind.length <= 1) {
    return;
  }

  const nextConfig = {
    ...resolvedConfig,
    tracks: resolvedConfig.tracks.filter((entry) => entry.id !== trackId),
    clips: resolvedConfig.clips.filter((clip) => clip.track !== trackId),
  };
  applyEdit({ type: 'config', resolvedConfig: nextConfig }, { selectedTrackId: null, semantic: true });
}, [applyEdit, resolvedConfig]);

const unusedTrackCount = useMemo(() => {
  if (!resolvedConfig) {
    return 0;
  }

  const tracksWithClips = new Set(resolvedConfig.clips.map((clip) => clip.track));
  const defaultTrackIds = new Set(DEFAULT_VIDEO_TRACKS.map((track) => track.id));

  // Count how many tracks would actually be removed (matching handleClearUnusedTracks logic).
  // We always keep at least one track per kind, even if it's empty.
  let keptEmptyVisual = false;
  let keptEmptyAudio = false;
  let removable = 0;

  for (const track of resolvedConfig.tracks) {
    if (defaultTrackIds.has(track.id) || tracksWithClips.has(track.id)) {
      continue;
    }

    if (track.kind === 'visual' && !keptEmptyVisual) {
      const hasVisualWithClips = resolvedConfig.tracks.some((t) => t.kind === 'visual' && tracksWithClips.has(t.id));
      if (!hasVisualWithClips) {
        keptEmptyVisual = true;
        continue;
      }
    }

    if (track.kind === 'audio' && !keptEmptyAudio) {
      const hasAudioWithClips = resolvedConfig.tracks.some((t) => t.kind === 'audio' && tracksWithClips.has(t.id));
      if (!hasAudioWithClips) {
        keptEmptyAudio = true;
        continue;
      }
    }

    removable++;
  }

  return removable;
}, [resolvedConfig]);

const handleClearUnusedTracks = useCallback(() => {
  if (!resolvedConfig || unusedTrackCount === 0) {
    return;
  }

  const tracksWithClips = new Set(resolvedConfig.clips.map((clip) => clip.track));
  const defaultTrackIds = new Set(DEFAULT_VIDEO_TRACKS.map((track) => track.id));
  const visualWithClips = resolvedConfig.tracks.filter((track) => track.kind === 'visual' && tracksWithClips.has(track.id));
  const audioWithClips = resolvedConfig.tracks.filter((track) => track.kind === 'audio' && tracksWithClips.has(track.id));

        const firstGroupAction = targetRow.actions.findIndex((action) => action.id === groupActions[0]?.id);
        const lastGroupAction = targetRow.actions.findIndex((action) => action.id === groupActions[groupActions.length - 1]?.id);
        if (firstGroupAction < 0 || lastGroupAction < 0) {
          continue;
        }

        const beforeActions = targetRow.actions.slice(0, firstGroupAction);
        const afterActions = targetRow.actions.slice(lastGroupAction + 1);
        const beforeActionIds = new Set(beforeActions.map((action) => action.id));
        const afterActionIds = new Set(afterActions.map((action) => action.id));
        const originalGroupEnd = groupActions[groupActions.length - 1]?.end ?? groupActions[0].end;
        const averageDuration = getAverageDuration(groupActions);
        const groupActionById = new Map(groupActions.map((action) => [action.id, action]));
        const availableClipIds = [...group.clipIds];

        let groupWorkingData: TimelineData = {
          ...workingData,
          rows: workingData.rows.map((row, rowIndex) => (
            rowIndex === targetRowIndex
              ? { ...row, actions: [...beforeActions] }
              : row
          )),
          clipOrder: {
            ...workingData.clipOrder,
            [group.trackId]: (workingData.clipOrder[group.trackId] ?? []).filter((clipId) => beforeActionIds.has(clipId)),
          },
        };

        const nextGroupChildren: NonNullable<PinnedShotGroup['children']> = [];
        const usedClipIds = new Set<string>();
        // Soft-tag groups don't carry `start`; derive from the first live action.
        const groupStart: number = group.start ?? groupActions[0]?.start ?? 0;
        let cursor: number = groupStart;

        for (const desiredImage of desiredImages) {
          const desiredGenerationId = desiredImage.generation_id;
          if (typeof desiredGenerationId !== 'string' || desiredGenerationId.length === 0) {
            continue;
          }

          const reusableClipId = availableClipIds.find((clipId) => (
            !usedClipIds.has(clipId)
            && getClipGenerationId(workingData, clipId) === desiredGenerationId
          ));

          if (reusableClipId) {
            const sourceAction = groupActionById.get(reusableClipId);
            const duration = sourceAction
              ? Math.max(0.05, sourceAction.end - sourceAction.start)
              : averageDuration;
            const offset = Math.max(0, cursor - groupStart);
            const action: TimelineAction = {
              id: reusableClipId,
              start: cursor,
              end: cursor + duration,
              effectId: `effect-${reusableClipId}`,
            };
            groupWorkingData = appendActionToTrack({
              current: groupWorkingData,
              trackId: group.trackId,
              action,
            });
            nextGroupChildren.push({
              clipId: reusableClipId,
              offset,
              duration,
            });
            usedClipIds.add(reusableClipId);
            cursor = action.end;
            continue;
          }

          const assetKey = registerGenerationAsset({
            generationId: desiredGenerationId,
            variantType: 'image',
            imageUrl: desiredImage.imageUrl ?? desiredImage.location ?? '',
            thumbUrl: desiredImage.thumbUrl ?? (desiredImage as { thumbnail_url?: string }).thumbnail_url ?? desiredImage.imageUrl ?? desiredImage.location ?? '',
            metadata: {
              content_type: desiredImage.contentType ?? desiredImage.type ?? 'image/png',
            },
          });
          if (!assetKey) {
            continue;
          }

          const latestRegistryEntry = dataRef.current?.registry.assets[assetKey];
          if (latestRegistryEntry) {
            groupWorkingData = {
              ...groupWorkingData,
              registry: {
                ...groupWorkingData.registry,
                assets: {
                  ...groupWorkingData.registry.assets,
                  [assetKey]: latestRegistryEntry,
                },
              },
            };
          }

          const nextEdit = buildAssetDropEdit({
            current: groupWorkingData,
            assetKey,
            trackId: group.trackId,
            time: cursor,
          });
          if (!nextEdit) {
            continue;
          }

          Object.assign(accumulatedMetaUpdates, nextEdit.metaUpdates);
          nextGroupChildren.push({
            clipId: nextEdit.clipId,
            offset: Math.max(0, cursor - groupStart),
            duration: nextEdit.duration,
          });
          cursor += nextEdit.duration;
          groupWorkingData = {
            ...groupWorkingData,
            rows: nextEdit.rows,
            meta: {
              ...groupWorkingData.meta,
              ...nextEdit.metaUpdates,
            },
            clipOrder: nextEdit.clipOrderOverride,
          };
        }

        const nextGroupClipIds = nextGroupChildren.map((child) => child.clipId);
        const removedClipIds = group.clipIds.filter((clipId) => !nextGroupClipIds.includes(clipId));
        for (const clipId of removedClipIds) {
          accumulatedMetaDeletes.add(clipId);
        }

        const afterShift = cursor - originalGroupEnd;
        const shiftedAfterActions = afterActions.map((action) => ({
          ...action,
          start: action.start + afterShift,
          end: action.end + afterShift,
        }));
        const rebuiltRow = groupWorkingData.rows[targetRowIndex];
        const nextRows = groupWorkingData.rows.map((row, rowIndex) => (
          rowIndex === targetRowIndex
            ? { ...row, actions: [...rebuiltRow.actions, ...shiftedAfterActions] }
            : row
        ));
        const nextClipOrder = {
          ...groupWorkingData.clipOrder,
          [group.trackId]: [
            ...(groupWorkingData.clipOrder[group.trackId] ?? []),
            ...(workingData.clipOrder[group.trackId] ?? []).filter((clipId) => afterActionIds.has(clipId)),
          ],
        };

        const nextConfig = replaceGroupChildren(
          {
            ...workingData.config,
            pinnedShotGroups: workingPinnedShotGroups,
          },
          {
            shotId: group.shotId,
            trackId: group.trackId,
          },
          nextGroupChildren,
        );
        const nextGroups = (nextConfig.pinnedShotGroups ?? [])
          .map(clonePinnedShotGroup)
          .filter((candidate) => (
            candidate.shotId !== group.shotId
            || candidate.trackId !== group.trackId
            || candidate.clipIds.length > 0
          ));

        workingPinnedShotGroups = nextGroups;
        workingData = {
          ...groupWorkingData,
          config: {
            ...groupWorkingData.config,
            pinnedShotGroups: nextGroups,
          },
          rows: nextRows,
          clipOrder: nextClipOrder,
        };
        hasChanges = true;
      }

      if (!hasChanges) {
        return;
      }

      applyEdit({
        type: 'rows',
        rows: workingData.rows,
        metaUpdates: Object.keys(accumulatedMetaUpdates).length > 0 ? accumulatedMetaUpdates : undefined,
        metaDeletes: accumulatedMetaDeletes.size > 0 ? [...accumulatedMetaDeletes] : undefined,
        clipOrderOverride: workingData.clipOrder,
        pinnedShotGroupsOverride: workingPinnedShotGroups,
      });
    };

    scheduleSync();

    return () => {
      clearScheduledSync();
    };
  }, [applyEdit, data, dataRef, debounceMs, isInteractionActive, registerGenerationAsset, shots]);
}

    const existingPinnedGroups = current.config.pinnedShotGroups ?? [];
    const pinnedGroup = existingPinnedGroups.find((group) => (
      group.shotId === shotId
      && group.trackId === rowId
      && group.mode === 'video'
      && typeof group.videoAssetKey === 'string'
      && group.videoAssetKey.length > 0
    ));
    const videoClipId = pinnedGroup?.clipIds[0];
    const targetRow = current.rows.find((row) => row.id === rowId);
    const videoAction = videoClipId ? targetRow?.actions.find((action) => action.id === videoClipId) : undefined;
    const videoMeta = videoClipId ? current.meta[videoClipId] : undefined;
    const currentGenerationId = pinnedGroup?.videoAssetKey
      ? current.registry.assets[pinnedGroup.videoAssetKey]?.generationId
      : undefined;
    if (!pinnedGroup || !videoClipId || !videoAction || !videoMeta || currentGenerationId === finalVideo.id) {
      return;
    }

    const assetKey = registerFinalVideoAsset(finalVideo, patchRegistry, registerAsset);
    const nextPinnedShotGroups = existingPinnedGroups.map((group) => (
      group.shotId === shotId && group.trackId === rowId
        ? { ...group, videoAssetKey: assetKey }
        : group
    ));

    applyEdit({
      type: 'rows',
      rows: current.rows,
      metaUpdates: {
        [videoClipId]: {
          asset: assetKey,
        },
      },
      pinnedShotGroupsOverride: nextPinnedShotGroups,
    });
  }, [applyEdit, dataRef, finalVideoMap, patchRegistry, registerAsset]);

  const switchToImages = useCallback(({ shotId, rowId }: { shotId: string; rowId: string }) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    const existingPinnedGroups = current.config.pinnedShotGroups ?? [];
    const pinnedGroup = existingPinnedGroups.find((group) => (
      group.shotId === shotId
      && group.trackId === rowId
      && group.mode === 'video'
    ));
    const targetRow = current.rows.find((row) => row.id === rowId);
    const videoClipId = pinnedGroup?.clipIds[0];
    const videoActionIndex = targetRow?.actions.findIndex((action) => action.id === videoClipId) ?? -1;
    const videoAction = videoActionIndex >= 0 ? targetRow?.actions[videoActionIndex] : undefined;
    if (!pinnedGroup || !targetRow || !videoClipId || !videoAction || !pinnedGroup.imageClipSnapshot?.length) {
      return;
    }

    const restoredMetaUpdates: Record<string, ClipMeta> = {};
    let cursor = 0;
    const restoredChildren = pinnedGroup.imageClipSnapshot.map((snapshot) => {
      const clipMeta: ClipMeta = {
        ...snapshot.meta,
        asset: snapshot.assetKey,
        track: rowId,
      };
      restoredMetaUpdates[snapshot.clipId] = clipMeta;
      const duration = getClipDuration(clipMeta, videoAction);
      const child = {
        clipId: snapshot.clipId,
        offset: cursor,
        duration,
      };
      cursor += duration;
      return child;
    });
    const nextPinnedShotGroups = updatePinnedGroupWithChildren({
      config: current.config,
      shotId,
      trackId: rowId,
      start: pinnedGroup.start ?? 0,
      nextChildren: restoredChildren,
      mode: 'images',
      imageClipSnapshot: pinnedGroup.imageClipSnapshot,
    });
    const nextPinnedGroup = nextPinnedShotGroups.find((group) => (
      group.shotId === shotId
      && group.trackId === rowId
    ));
    if (!nextPinnedGroup) {
      return;
    }
    const groupStart = nextPinnedGroup.start ?? 0;
    const restoredActions = (nextPinnedGroup.children ?? []).map((child) => ({
      id: child.clipId,
      start: groupStart + child.offset,
      end: groupStart + child.offset + child.duration,
      effectId: `effect-${child.clipId}`,
    }));

    const nextRows = current.rows.map((row) => {
      if (row.id !== rowId) {
        return row;
      }

      const remainingActions = row.actions.filter((action) => action.id !== videoClipId);
      return {
        ...row,
        actions: [
          ...remainingActions.slice(0, videoActionIndex),
          ...restoredActions,
          ...remainingActions.slice(videoActionIndex),
        ],
      };
    });
    const nextClipOrder = updateClipOrder(current.clipOrder, rowId, (ids) => {
      const filtered = ids.filter((id) => id !== videoClipId);
      const insertionIndex = ids.indexOf(videoClipId);
      const restoredClipIds = pinnedGroup.imageClipSnapshot?.map((snapshot) => snapshot.clipId) ?? [];
      return insertionIndex < 0
        ? [...filtered, ...restoredClipIds]
        : [...filtered.slice(0, insertionIndex), ...restoredClipIds, ...filtered.slice(insertionIndex)];
    });

    applyEdit({
      type: 'rows',
      rows: nextRows,
      metaUpdates: restoredMetaUpdates,
      metaDeletes: [videoClipId],
      clipOrderOverride: nextClipOrder,
      pinnedShotGroupsOverride: nextPinnedShotGroups,
    });
  }, [applyEdit, dataRef]);

  return {
    switchToFinalVideo,
    updateToLatestVideo,
    switchToImages,
  };
}

