});

function makeCoordinator(overrides: Partial<ReturnType<DragCoordinator['update']>> = {}): DragCoordinator {
  const defaultPosition = {
    time: 0,
    rowIndex: 0,
    trackId: 'V1',
    trackKind: 'visual' as const,
    trackName: 'V1',
    isNewTrack: false,
    isNewTrackTop: false,
    isReject: false,
    newTrackKind: null,
    screenCoords: {
      rowTop: 0,
      rowLeft: 0,
      rowWidth: 0,
      rowHeight: 48,
      clipLeft: 0,
      clipWidth: 0,
      ghostCenter: 0,
    },
  };
  const coordinator = {
    update: vi.fn(() => {
      const nextPosition = {
        ...defaultPosition,
        ...overrides,
        screenCoords: {
          ...defaultPosition.screenCoords,
          ...overrides.screenCoords,
        },
      };
      coordinator.lastPosition = nextPosition;
      return nextPosition;
    }),
    showSecondaryGhosts: vi.fn(),
    end: vi.fn(),
    lastPosition: null,
    editAreaRef: { current: null },
  } satisfies DragCoordinator;

  return coordinator;
}

function canonicalizeTimelineData(data: TimelineData): TimelineData {
  const config = projectPinnedShotGroups(repairConfig(data.config as TimelineConfig));
  const rowData = configToRows(config);

  return {
    ...data,
    config,
    resolvedConfig: {
      ...data.resolvedConfig,
      output: { ...config.output },
      tracks: (config.tracks ?? []).map((track) => ({ ...track })),
      clips: config.clips.map((clip) => ({ ...clip })),
    },
    rows: rowData.rows,
    meta: rowData.meta,
    effects: rowData.effects,
    output: { ...config.output },
    tracks: (config.tracks ?? []).map((track) => ({ ...track })),
    clipOrder: rowData.clipOrder,
  };
}

