import type { PinnedShotGroup, TimelineConfig } from '@/tools/video-editor/types';
import type { TimelineRow } from '@/tools/video-editor/types/timeline-canvas';

export type PinnedGroupKey = Pick<PinnedShotGroup, 'shotId' | 'trackId'>;

export type CategorizedSelection = {
  freeClipIds: string[];
  groups: Array<{
    groupKey: PinnedGroupKey;
    clipIds: string[];
  }>;
};

const getGroupId = (groupKey: PinnedGroupKey): string => `${groupKey.shotId}:${groupKey.trackId}`;

/**
 * Find the pinned group that contains `clipId`, if any. Soft-tag lookup only —
 * returns the first group whose `clipIds` list includes the target.
 */
export function findEnclosingPinnedGroup(
  config: TimelineConfig,
  clipId: string,
): { group: PinnedShotGroup; groupKey: PinnedGroupKey; index: number } | null {
  const groups = config.pinnedShotGroups ?? [];
  const index = groups.findIndex((group) => group.clipIds.includes(clipId));
  if (index < 0) {
    return null;
  }

  const group = groups[index];
  return {
    group,
    groupKey: { shotId: group.shotId, trackId: group.trackId },
    index,
  };
}

/**
 * Split a selection of clip ids into free clips and enclosing groups. If any
 * clip in the selection belongs to a group, the group's full `clipIds` list is
 * used (selection expands to the whole group).
 */
export function categorizeSelection(
  clipIds: string[],
  config: TimelineConfig,
): CategorizedSelection {
  const uniqueClipIds = [...new Set(clipIds)];
  const freeClipIds: string[] = [];
  const groups = new Map<string, { groupKey: PinnedGroupKey; clipIds: string[] }>();

  for (const clipId of uniqueClipIds) {
    const enclosingGroup = findEnclosingPinnedGroup(config, clipId);
    if (!enclosingGroup) {
      freeClipIds.push(clipId);
      continue;
    }

    const groupId = getGroupId(enclosingGroup.groupKey);
    if (!groups.has(groupId)) {
      groups.set(groupId, {
        groupKey: enclosingGroup.groupKey,
        clipIds: [...enclosingGroup.group.clipIds],
      });
    }
  }

  return {
    freeClipIds,
    groups: [...groups.values()],
  };
}

interface OrderClipIdsByAtContext {
  clips?: TimelineConfig['clips'];
  rows?: TimelineRow[];
}

/**
 * Return `clipIds` sorted left-to-right by each clip's current live `at`.
 * Unknown clip ids are preserved at their existing relative order at the end.
 * Accepts either a `clips[]` snapshot (from a TimelineConfig) or live `rows`
 * (from TimelineData) — whichever is more convenient at the call site.
 */
export function orderClipIdsByAt(
  clipIds: readonly string[],
  context: OrderClipIdsByAtContext,
): string[] {
  const atById = new Map<string, number>();

  if (context.clips) {
    for (const clip of context.clips) {
      atById.set(clip.id, clip.at);
    }
  }
  if (context.rows) {
    for (const row of context.rows) {
      for (const action of row.actions) {
        // Only overwrite if not already set (clips wins if both provided).
        if (!atById.has(action.id)) {
          atById.set(action.id, action.start);
        }
      }
    }
  }

  const known: Array<{ id: string; at: number; originalIndex: number }> = [];
  const unknown: string[] = [];
  clipIds.forEach((id, originalIndex) => {
    const at = atById.get(id);
    if (typeof at === 'number') {
      known.push({ id, at, originalIndex });
    } else {
      unknown.push(id);
    }
  });

  known.sort((left, right) => {
    if (left.at !== right.at) return left.at - right.at;
    return left.originalIndex - right.originalIndex;
  });

  return [...known.map((entry) => entry.id), ...unknown];
}

// ─────────────────────────────────────────────────────────────────────
// Legacy projection-model shims (compatibility layer during rollback).
//
// These exist so production callsites that haven't been migrated to the
// soft-tag model still type-check and run. They produce soft-tag
// PinnedShotGroups (no `start`, no `children`) and ignore any legacy
// projection-shape inputs they're passed. Once every callsite is
// migrated, delete this section.
// ─────────────────────────────────────────────────────────────────────

type LegacyChild = { clipId: string; offset?: number; duration?: number };

interface BuildGroupFromChildrenArgs {
  shotId: string;
  trackId: string;
  /** @deprecated Ignored — clips carry their own positions in the soft-tag model. */
  start?: number;
  children?: LegacyChild[];
  mode?: PinnedShotGroup['mode'];
  videoAssetKey?: PinnedShotGroup['videoAssetKey'];
  imageClipSnapshot?: PinnedShotGroup['imageClipSnapshot'];
}

/**
 * @deprecated Compatibility shim. Returns a soft-tag PinnedShotGroup
 * derived from the (possibly legacy projection-shape) input. The `start`
 * and child `offset`/`duration` fields are ignored — clips carry their
 * own positions now.
 */
export function buildGroupFromChildren(args: BuildGroupFromChildrenArgs): PinnedShotGroup {
  const clipIds = (args.children ?? []).map((child) => child.clipId);
  return {
    shotId: args.shotId,
    trackId: args.trackId,
    clipIds,
    mode: args.mode,
    videoAssetKey: args.videoAssetKey,
    imageClipSnapshot: args.imageClipSnapshot,
  };
}

interface BuildGroupFromConfigClipsArgs {
  shotId: string;
  trackId: string;
  clipIds: string[];
  config: TimelineConfig;
  mode?: PinnedShotGroup['mode'];
  videoAssetKey?: PinnedShotGroup['videoAssetKey'];
  imageClipSnapshot?: PinnedShotGroup['imageClipSnapshot'];
}

/**
 * @deprecated Compatibility shim. Builds a soft-tag PinnedShotGroup with
 * `clipIds` sorted left-to-right by each clip's live `at`.
 */
export function buildGroupFromConfigClips(args: BuildGroupFromConfigClipsArgs): PinnedShotGroup {
  const orderedClipIds = orderClipIdsByAt(args.clipIds, { clips: args.config.clips });
  return {
    shotId: args.shotId,
    trackId: args.trackId,
    clipIds: orderedClipIds,
    mode: args.mode,
    videoAssetKey: args.videoAssetKey,
    imageClipSnapshot: args.imageClipSnapshot,
  };
}

/**
 * @deprecated Compatibility shim. In the soft-tag model, "replacing children"
 * just means setting the group's `clipIds`. The `offset`/`duration` fields are
 * ignored — clips carry their own positions.
 */
export function replaceGroupChildren(
  config: TimelineConfig,
  groupKey: PinnedGroupKey,
  nextChildren: LegacyChild[],
): TimelineConfig {
  if (!config.pinnedShotGroups?.length) {
    return config;
  }
  const nextClipIds = nextChildren.map((child) => child.clipId);
  return {
    ...config,
    pinnedShotGroups: config.pinnedShotGroups.map((group) => (
      group.shotId === groupKey.shotId && group.trackId === groupKey.trackId
        ? { ...group, clipIds: nextClipIds }
        : group
    )),
  };
}

/**
 * @deprecated Compatibility shim. In the soft-tag model, moving a group
 * across rows updates only the group's `trackId`. The `nextStart` argument
 * is ignored — clip positions are managed directly by the caller.
 */
export function moveGroup(
  config: TimelineConfig,
  groupKey: PinnedGroupKey,
  _nextStart: number,
  nextTrackId?: string,
): TimelineConfig {
  if (!config.pinnedShotGroups?.length) {
    return config;
  }
  return {
    ...config,
    pinnedShotGroups: config.pinnedShotGroups.map((group) => (
      group.shotId === groupKey.shotId && group.trackId === groupKey.trackId
        ? { ...group, trackId: nextTrackId ?? group.trackId }
        : group
    )),
  };
}

/**
 * @deprecated Compatibility shim. Soft-tag model has no projection — clips
 * are the source of truth. This is a pass-through that strips legacy
 * `start`/`children` fields from any groups that still carry them and
 * ensures `clipIds` is set.
 */
export function projectPinnedShotGroups(config: TimelineConfig): TimelineConfig {
  if (!config.pinnedShotGroups?.length) {
    return config;
  }
  let changed = false;
  const nextGroups = config.pinnedShotGroups.map((group) => {
    const hasLegacy = 'start' in group || 'children' in group;
    if (!hasLegacy && group.clipIds) {
      return group;
    }
    changed = true;
    const clipIds = group.clipIds && group.clipIds.length > 0
      ? group.clipIds
      : (group.children ?? []).map((child) => child.clipId);
    const next: PinnedShotGroup = {
      shotId: group.shotId,
      trackId: group.trackId,
      clipIds,
      mode: group.mode,
      videoAssetKey: group.videoAssetKey,
      imageClipSnapshot: group.imageClipSnapshot,
    };
    return next;
  });
  return changed ? { ...config, pinnedShotGroups: nextGroups } : config;
}

