          x: 658,
          y: 0,
          width: 2256,
          height: 1692,
          cropRight: 0.53,
          cropBottom: 0.53,
          opacity: 1,
        },
      ],
      pinnedShotGroups: [
        {
          shotId: 'shot-1',
          trackId: 'V1',
          clipIds: ['clip-1'],
          mode: 'images',
        },
      ],
    };
    const nextConfig = roundTripConfig(config);
    const [nextClip] = nextConfig.clips;

    expect(nextClip).toMatchObject({
      id: 'clip-1',
      x: 658,
      y: 0,
