export const DebugTrack: FC<{ src: string }> = ({ src }) => {
  const frame = useCurrentFrame();
  const { fps, width, height, durationInFrames } = useVideoConfig();
  const mountTime = useRef(Date.now());
  const lastLogFrame = useRef(-1);

