export function useCreateSession(timelineId: string | null | undefined) {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async () => {
      if (!timelineId) {
        throw new Error('timelineId is required');
      }

      const { data: authData, error: authError } = await getSupabaseClient().auth.getUser();
      if (authError) {
        throw authError;
      }

      const userId = authData.user?.id;
      if (!userId) {
        throw new Error('User not authenticated');
      }

      const { data, error } = await getSupabaseClient()
        .from(TIMELINE_AGENT_SESSIONS_TABLE as never)
        .insert({
          timeline_id: timelineId,
          user_id: userId,
          status: 'waiting_user',
          turns: [],
          model: 'groq',
        })
        .select('*')
        .single();

      if (error) {
        throw error;
      }

      return normalizeSession(data);
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: agentSessionsQueryKey(timelineId) });
    },
  });
}

export function useSendMessage(sessionId: string | null | undefined, timelineId?: string | null) {
  const queryClient = useQueryClient();
  const timeoutIdsRef = useRef<Set<number>>(new Set());
  const lastMessageRef = useRef<SendMessageInput | null>(null);
  const [continuationNotice, setContinuationNotice] = useState<string | null>(null);
  const [localError, setLocalError] = useState<string | null>(null);

  useEffect(() => {
    const timeoutIds = timeoutIdsRef.current;
    return () => {
      for (const timeoutId of timeoutIds) {
        window.clearTimeout(timeoutId);
      }
      timeoutIds.clear();
    };
  }, []);

  const mutation = useMutation({
    mutationFn: async (input: SendMessageInput) => {
      if (!sessionId) {
        throw new Error('sessionId is required');
      }

      const { message, attachments } = input;
      lastMessageRef.current = {
        message,
        attachments,
      };
      setLocalError(null);

      const invokeAgent = async (
        nextUserMessage?: string,
        continueCount = 0,
      ): Promise<AgentInvocationResponse> => {
        const { data, error } = await getSupabaseClient().functions.invoke('ai-timeline-agent', {
          body: {
            session_id: sessionId,
            ...(nextUserMessage ? { user_message: nextUserMessage } : {}),
            ...(nextUserMessage && attachments?.length ? {
              selected_clips: attachments.map((clip) => ({
                clip_id: clip.clipId,
                url: clip.url,
                media_type: clip.mediaType,
                ...(clip.generationId ? { generation_id: clip.generationId } : {}),
                ...(clip.prompt ? { prompt: clip.prompt } : {}),
              })),
            } : {}),
          },
        });

        if (error) {
          // Supabase functions.invoke returns a generic "Edge Function returned a non-2xx status code"
          // message in `error`, but the actual error details are in `data`.
          const detail = typeof data === 'object' && data !== null
            ? (data as Record<string, unknown>).error ?? (data as Record<string, unknown>).details ?? (data as Record<string, unknown>).message
            : undefined;
          if (detail && typeof detail === 'string') {
            throw new Error(detail);
          }
          throw error;
        }

        const response = normalizeInvokeResponse(data);

        if (response.status !== 'continue') {
          setContinuationNotice(null);
          return response;
        }

        if (continueCount >= AUTO_CONTINUE_LIMIT) {
          setContinuationNotice(
            `Auto-continuation paused after ${AUTO_CONTINUE_LIMIT} consecutive continue responses.`,
          );
          return response;
        }

        setContinuationNotice('Agent is continuing...');
        await delayWithTracking(timeoutIdsRef, AUTO_CONTINUE_DELAY_MS);
        return invokeAgent(undefined, continueCount + 1);
      };

      return invokeAgent(message, 0);
    },
    onError: (error) => {
      // Only show error briefly — it will be cleared if realtime delivers a successful update
      setLocalError(toErrorMessage(error));
      // Auto-clear after 5s to avoid stale error banners
      const clearId = window.setTimeout(() => setLocalError(null), 5000);
      timeoutIdsRef.current.add(clearId);
    },
    onSuccess: () => {
      setLocalError(null);
      void queryClient.invalidateQueries({ queryKey: agentSessionQueryKey(sessionId) });
      void queryClient.invalidateQueries({ queryKey: ['timeline-agent-sessions'] });
      // Re-fetch the timeline so agent edits appear immediately in the editor
      if (timelineId) {
        void queryClient.invalidateQueries({ queryKey: timelineQueryKey(timelineId) });
      }
    },
  });

  const retryLastMessage = async () => {
    if (!lastMessageRef.current) {
      return null;
    }

    setLocalError(null);
    return mutation.mutateAsync(lastMessageRef.current);
  };

  return {
    continuationNotice,
    clearContinuationNotice: () => setContinuationNotice(null),
    localError,
    clearLocalError: () => setLocalError(null),
    hasRetryableMessage: Boolean(lastMessageRef.current),
    retryLastMessage,
    ...mutation,
  };
}

export function useCancelSession(sessionId: string | null | undefined) {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async () => {
      if (!sessionId) {
        throw new Error('sessionId is required');
      }

      const { error } = await getSupabaseClient()
        .from(TIMELINE_AGENT_SESSIONS_TABLE as never)
        .update({
          status: 'cancelled',
          updated_at: new Date().toISOString(),
        })
        .eq('id', sessionId);

      if (error) {
        throw error;
      }
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: agentSessionQueryKey(sessionId) });
      void queryClient.invalidateQueries({ queryKey: ['timeline-agent-sessions'] });
    },
  });
}

import { useMemo } from 'react';
import type { UseMutationOptions, UseMutationResult } from '@tanstack/react-query';
import {
  useCreateResource,
  useDeleteResource,
  useListPublicResources,
  useListResources,
  useUpdateResource,
  type EffectMetadata,
  type Resource,
} from '@/features/resources/hooks/useResources';

export type EffectCategory = EffectMetadata['category'];

export type EffectResource = EffectMetadata & {
  id: string;
  type: 'effect';
  userId?: string;
  user_id?: string;
  isPublic?: boolean;
  is_public?: boolean;
  createdAt?: string;
  created_at?: string;
};

export type EffectResourcesByCategory = Record<EffectCategory, EffectResource[]>;

const EMPTY_EFFECT_GROUPS: EffectResourcesByCategory = {
  entrance: [],
  exit: [],
  continuous: [],
};

function toEffectResource(resource: Resource): EffectResource {
  const metadata = resource.metadata as EffectMetadata;
  return {
    id: resource.id,
    type: 'effect',
    userId: resource.userId,
    user_id: resource.user_id,
    isPublic: resource.isPublic,
    is_public: resource.is_public,
    createdAt: resource.createdAt,
    created_at: resource.created_at,
    ...metadata,
  };
}

function dedupeEffectResources(resources: Resource[]): EffectResource[] {
  const deduped = new Map<string, EffectResource>();

  for (const resource of resources) {
    deduped.set(resource.id, toEffectResource(resource));
  }

  return [...deduped.values()];
}

function groupEffectResources(resources: EffectResource[]): EffectResourcesByCategory {
  return resources.reduce<EffectResourcesByCategory>((groups, resource) => {
    groups[resource.category].push(resource);
    return groups;
  }, {
    entrance: [],
    exit: [],
    continuous: [],
  });
}

export function useEffectResources(userId: string | null | undefined) {
  const privateEffectsQuery = useListResources('effect');
  const publicEffectsQuery = useListPublicResources('effect');

  const effects = useMemo(() => {
    const privateResources = userId ? privateEffectsQuery.data ?? [] : [];
    const publicResources = publicEffectsQuery.data ?? [];
    return dedupeEffectResources([...privateResources, ...publicResources]);
  }, [privateEffectsQuery.data, publicEffectsQuery.data, userId]);

  const byCategory = useMemo(() => {
    if (effects.length === 0) {
      return EMPTY_EFFECT_GROUPS;
    }

    return groupEffectResources(effects);
  }, [effects]);

  return {
    data: byCategory,
    effects,
    entrance: byCategory.entrance,
    exit: byCategory.exit,
    continuous: byCategory.continuous,
    isLoading: privateEffectsQuery.isLoading || publicEffectsQuery.isLoading,
    isFetching: privateEffectsQuery.isFetching || publicEffectsQuery.isFetching,
    error: privateEffectsQuery.error ?? publicEffectsQuery.error ?? null,
    refetch: async () => {
      const results = await Promise.all([privateEffectsQuery.refetch(), publicEffectsQuery.refetch()]);
      return results;
    },
    privateEffectsQuery,
    publicEffectsQuery,
  };
}

export function useCreateEffectResource(): Omit<
  UseMutationResult<Resource, Error, { metadata: EffectMetadata }, unknown>,
  'mutate' | 'mutateAsync'
> & {
  mutate: UseMutationResult<Resource, Error, { metadata: EffectMetadata }, unknown>['mutate'];
  mutateAsync: (variables: { metadata: EffectMetadata }, options?: UseMutationOptions<Resource, Error, { metadata: EffectMetadata }, unknown>) => Promise<Resource>;
} {
  const mutation = useCreateResource();

  return {
    ...mutation,
    mutate: (variables, options) => mutation.mutate({ type: 'effect', metadata: variables.metadata }, options),
    mutateAsync: (variables, options) => mutation.mutateAsync({ type: 'effect', metadata: variables.metadata }, options),
  };
}

export function useUpdateEffectResource(): Omit<
  UseMutationResult<Resource, Error, { id: string; metadata: EffectMetadata }, unknown>,
  'mutate' | 'mutateAsync'
> & {
  mutate: UseMutationResult<Resource, Error, { id: string; metadata: EffectMetadata }, unknown>['mutate'];
  mutateAsync: (variables: { id: string; metadata: EffectMetadata }, options?: UseMutationOptions<Resource, Error, { id: string; metadata: EffectMetadata }, unknown>) => Promise<Resource>;
} {
  const mutation = useUpdateResource();

  return {
    ...mutation,
    mutate: (variables, options) => mutation.mutate({ id: variables.id, type: 'effect', metadata: variables.metadata }, options),
    mutateAsync: (variables, options) => mutation.mutateAsync({ id: variables.id, type: 'effect', metadata: variables.metadata }, options),
  };
}

export function useDeleteEffectResource(): Omit<
  UseMutationResult<void, Error, { id: string }, unknown>,
  'mutate' | 'mutateAsync'
> & {
  mutate: UseMutationResult<void, Error, { id: string }, unknown>['mutate'];
  mutateAsync: (variables: { id: string }, options?: UseMutationOptions<void, Error, { id: string }, unknown>) => Promise<void>;
} {
  const mutation = useDeleteResource();

  return {
    ...mutation,
    mutate: (variables, options) => mutation.mutate({ id: variables.id, type: 'effect' }, options),
    mutateAsync: (variables, options) => mutation.mutateAsync({ id: variables.id, type: 'effect' }, options),
  };
}

import { getSupabaseClient } from '@/integrations/supabase/client';
import { generateUUID } from '@/shared/lib/taskCreation/ids';
import { validateSerializedConfig } from '@/tools/video-editor/lib/serialize';
import { createDefaultTimelineConfig } from '@/tools/video-editor/lib/defaults';
import { extractAssetRegistryEntry } from '@/tools/video-editor/lib/mediaMetadata';
import {
  TimelineNotFoundError,
  TimelineVersionConflictError,
  type DataProvider,
  type LoadedTimeline,
  type UploadAssetOptions,
} from '@/tools/video-editor/data/DataProvider';
import type { AssetRegistry, AssetRegistryEntry, TimelineConfig } from '@/tools/video-editor/types';
import type { Checkpoint } from '@/tools/video-editor/types/history';

const TIMELINE_ASSETS_BUCKET = 'timeline-assets';
const TIMELINE_CHECKPOINT_LIMIT = 30;
const TIMELINE_CHECKPOINT_RETENTION_MS = 24 * 60 * 60 * 1000;


type TimelineCheckpointRow = {
  id: string;
  timeline_id: string;
  config: TimelineConfig;
  created_at: string;
  trigger_type: Checkpoint['triggerType'];
  label: string;
  edits_since_last_checkpoint: number;
};

function mapCheckpointRow(row: TimelineCheckpointRow): Checkpoint {
  return {
    id: row.id,
    timelineId: row.timeline_id,
    config: row.config,
    createdAt: row.created_at,
    triggerType: row.trigger_type,
    label: row.label,
    editsSinceLastCheckpoint: row.edits_since_last_checkpoint,
  };
}

export class SupabaseDataProvider implements DataProvider {
  constructor(
    private readonly options: {
      projectId: string;  // Retained for callers but not used in queries — RLS handles access control.
      userId: string;     // Used only for checkpoint inserts (DB column value, not query filter).
    },
  ) {}

  async loadTimeline(timelineId: string): Promise<LoadedTimeline> {
    const { data, error } = await getSupabaseClient()
      .from('timelines')
      .select('config, config_version')
      .eq('id', timelineId)
      .maybeSingle();

    if (error) {
      throw error;
    }

    const config = (data?.config ?? createDefaultTimelineConfig()) as TimelineConfig;
    validateSerializedConfig(config);

    return {
      config,
      configVersion: typeof (data as { config_version?: unknown } | null)?.config_version === 'number'
        ? (data as { config_version: number }).config_version
        : 1,
    };
  }

  async saveTimeline(timelineId: string, config: TimelineConfig, expectedVersion: number): Promise<number> {
    validateSerializedConfig(config);

    const { data, error } = await getSupabaseClient()
      .rpc('update_timeline_config_versioned' as never, {
        p_timeline_id: timelineId,
        p_expected_version: expectedVersion,
        p_config: config,
      } as never);

    if (error) {
      throw error;
    }

    const rows = data as Array<{ config_version: number }> | null;
    if (!rows || rows.length === 0) {
      throw new TimelineVersionConflictError();
    }

    return rows[0].config_version;
  }

  async saveCheckpoint(timelineId: string, checkpoint: Omit<Checkpoint, 'id'>): Promise<string> {
    validateSerializedConfig(checkpoint.config);

    const supabase = getSupabaseClient();
    const { data, error } = await supabase
      .from('timeline_checkpoints')
      .insert({
        timeline_id: timelineId,
        user_id: this.options.userId,
        config: checkpoint.config,
        trigger_type: checkpoint.triggerType,
        label: checkpoint.label,
        edits_since_last_checkpoint: checkpoint.editsSinceLastCheckpoint,
        created_at: checkpoint.createdAt,
      })
      .select('id')
      .single();

    if (error) {
      throw error;
    }

    const { data: checkpointRows, error: checkpointRowsError } = await supabase
      .from('timeline_checkpoints')
      .select('id, trigger_type')
      .eq('timeline_id', timelineId)
      .neq('trigger_type', 'manual')
      .order('created_at', { ascending: false });

    if (checkpointRowsError) {
      throw checkpointRowsError;
    }

    const extraCheckpointIds = (checkpointRows ?? [])
      .slice(TIMELINE_CHECKPOINT_LIMIT)
      .map((row) => row.id)
      .filter((id): id is string => typeof id === 'string');

    if (extraCheckpointIds.length > 0) {
      const { error: deleteError } = await supabase
        .from('timeline_checkpoints')
        .delete()
        .in('id', extraCheckpointIds);

      if (deleteError) {
        throw deleteError;
      }
    }

    return data.id;
  }

  async loadCheckpoints(timelineId: string): Promise<Checkpoint[]> {
    const supabase = getSupabaseClient();
    const retentionCutoff = new Date(Date.now() - TIMELINE_CHECKPOINT_RETENTION_MS).toISOString();

    const { error: cleanupError } = await supabase
      .from('timeline_checkpoints')
      .delete()
      .eq('timeline_id', timelineId)
      .neq('trigger_type', 'manual')
      .lt('created_at', retentionCutoff);

    if (cleanupError) {
      throw cleanupError;
    }

    const { data, error } = await supabase
      .from('timeline_checkpoints')
      .select('id, timeline_id, config, created_at, trigger_type, label, edits_since_last_checkpoint')
      .eq('timeline_id', timelineId)
      .order('created_at', { ascending: false });

    if (error) {
      throw error;
    }

    return (data ?? []).map((row) => mapCheckpointRow(row as TimelineCheckpointRow));
  }

  async loadAssetRegistry(timelineId: string): Promise<AssetRegistry> {
    const { data, error } = await getSupabaseClient()
      .from('timelines')
      .select('asset_registry')
      .eq('id', timelineId)
      .maybeSingle();

    if (error) {
      throw error;
    }

    return (data?.asset_registry as AssetRegistry | null) ?? { assets: {} };
  }

  async resolveAssetUrl(file: string): Promise<string> {
    if (/^https?:\/\//.test(file)) {
      return file;
    }

    const { data } = getSupabaseClient()
      .storage
      .from(TIMELINE_ASSETS_BUCKET)
      .getPublicUrl(file);

    return data.publicUrl;
  }

  async registerAsset(
    timelineId: string,
    assetId: string,
    entry: AssetRegistryEntry,
  ): Promise<void> {
    const { error } = await getSupabaseClient()
      .rpc('upsert_asset_registry_entry' as never, {
        p_timeline_id: timelineId,
        p_asset_id: assetId,
        p_entry: entry,
      } as never);

    if (error) {
      throw error;
    }
  }

  async uploadAsset(
    file: File,
    options: UploadAssetOptions,
  ): Promise<{ assetId: string; entry: Awaited<ReturnType<typeof extractAssetRegistryEntry>> }> {
    const safeFilename = (options.filename ?? file.name)
      .replace(/\s+/g, '-')
      .replace(/[^a-zA-Z0-9._-]/g, '');
    const storagePath = `${options.userId}/${options.timelineId}/${Date.now()}-${safeFilename}`;

    const { error: uploadError } = await getSupabaseClient()
      .storage
      .from(TIMELINE_ASSETS_BUCKET)
      .upload(storagePath, file, {
        upsert: false,
        contentType: file.type || undefined,
      });

    if (uploadError) {
      throw uploadError;
    }

    const entry = await extractAssetRegistryEntry(file, storagePath);
    const assetId = generateUUID();
    await this.registerAsset(options.timelineId, assetId, entry);

    return { assetId, entry };
  }

  async loadWaveform(): Promise<null> {
    return null;
  }

  async loadAssetProfile(): Promise<null> {
    return null;
  }
}

import { useMemo } from 'react';
import { useTimelineEditorData } from '@/tools/video-editor/contexts/TimelineEditorContext';

export type SelectedMediaClip = {
  clipId: string;
  assetKey: string;
  url: string;
  mediaType: 'image' | 'video';
  generationId?: string;
};

function formatAttachmentCount(count: number, mediaType: 'image' | 'video') {
  if (count === 1) {
    return `1 ${mediaType}`;
  }

  return `${count} ${mediaType}s`;
}

export function buildSummary(imageCount: number, videoCount: number) {
  const parts = [
    imageCount > 0 ? formatAttachmentCount(imageCount, 'image') : null,
    videoCount > 0 ? formatAttachmentCount(videoCount, 'video') : null,
  ].filter((part): part is string => part !== null);

  return parts.length > 0 ? `attaching ${parts.join(', ')}` : '';
}

export function useSelectedMediaClips(): { clips: SelectedMediaClip[]; summary: string } {
  const { selectedClipIds, resolvedConfig } = useTimelineEditorData();

  return useMemo(() => {
    if (!resolvedConfig || selectedClipIds.size === 0) {
      return { clips: [], summary: '' };
    }

    const clips = [...selectedClipIds].flatMap((clipId) => {
      const clip = resolvedConfig.clips.find((item) => item.id === clipId);
      const assetKey = clip?.asset;
      const assetEntry = assetKey ? resolvedConfig.registry[assetKey] : undefined;

      if (!assetKey || !assetEntry?.src || !assetEntry.type) {
        return [];
      }

      if (assetEntry.type.startsWith('image/')) {
        return [{
          clipId,
          assetKey,
          url: assetEntry.src,
          mediaType: 'image' as const,
          generationId: assetEntry.generationId,
        }];
      }

      if (assetEntry.type.startsWith('video/')) {
        return [{
          clipId,
          assetKey,
          url: assetEntry.src,
          mediaType: 'video' as const,
          generationId: assetEntry.generationId,
        }];
      }

      return [];
    });

    const imageCount = clips.filter((clip) => clip.mediaType === 'image').length;
    const videoCount = clips.length - imageCount;

    return {
      clips,
      summary: buildSummary(imageCount, videoCount),
    };
  }, [resolvedConfig, selectedClipIds]);
}

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { getSupabaseClient } from '@/integrations/supabase/client';
import { createDefaultTimelineConfig } from '@/tools/video-editor/lib/defaults';

export const timelineListQueryKey = (projectId: string | null | undefined) => ['timelines', projectId] as const;

export function useTimelinesList(projectId: string | null | undefined, userId: string | null | undefined) {
  const queryClient = useQueryClient();

  const timelinesQuery = useQuery({
    queryKey: timelineListQueryKey(projectId),
    enabled: Boolean(projectId),
    queryFn: async () => {
      const { data, error } = await getSupabaseClient()
        .from('timelines')
        .select('*')
        .eq('project_id', projectId!)
        .order('updated_at', { ascending: false });

      if (error) {
        throw error;
      }

      return data ?? [];
    },
  });

  const invalidate = () => queryClient.invalidateQueries({ queryKey: timelineListQueryKey(projectId) });

  const createTimeline = useMutation({
    mutationFn: async (name: string) => {
      const { data, error } = await getSupabaseClient()
        .from('timelines')
        .insert({
          name,
          project_id: projectId!,
          user_id: userId!,
          config: createDefaultTimelineConfig(),
          asset_registry: { assets: {} },
        })
        .select('*')
        .single();

      if (error) {
        throw error;
      }

      return data;
    },
    onSuccess: () => {
      void invalidate();
    },
  });

  const renameTimeline = useMutation({
    mutationFn: async ({ timelineId, name }: { timelineId: string; name: string }) => {
      const { error } = await getSupabaseClient()
        .from('timelines')
        .update({ name, updated_at: new Date().toISOString() })
        .eq('id', timelineId);

      if (error) {
        throw error;
      }
    },
    onSuccess: () => {
      void invalidate();
    },
  });

  const deleteTimeline = useMutation({
    mutationFn: async (timelineId: string) => {
      const { error } = await getSupabaseClient()
        .from('timelines')
        .delete()
        .eq('id', timelineId);

      if (error) {
        throw error;
      }
    },
    onSuccess: () => {
      void invalidate();
    },
  });

  return {
    ...timelinesQuery,
    createTimeline,
    renameTimeline,
    deleteTimeline,
  };
}

